// packages/domain/src/catalog/domain/extract-puzzle-draft.ts
import { cleanPuzzleTitle } from "./clean-puzzle-title";
import { hasUnsupportedImageExtension } from "./image-format";
import type {
  JsonLdProduct,
  PuzzleImportDraft,
  RawProductPage,
} from "./puzzle-import-draft";

// Multilingual piece-count: EN pieces/pcs, NL stukjes, DE Teile, ES piezas, FR pieces. Captures
// an integer that may carry `.`/`,`/space thousands separators (e.g. "1.000", "1,500").
const PIECE_COUNT_RE =
  /(\d[\d.,\s]{0,7}\d|\d)\s*(?:pieces?|pcs|stukjes|teile|piezas|pi[eè]ces)\b/i;

const parsePieceCount = (text: string): number | undefined => {
  const match = text.match(PIECE_COUNT_RE);
  if (!match) return undefined;
  const n = Number.parseInt(match[1].replace(/[.,\s]/g, ""), 10);
  return Number.isFinite(n) && n >= 1 && n <= 100000 ? n : undefined;
};

const toImageArray = (
  image: string | readonly string[] | undefined,
): readonly string[] => {
  // Stryker disable next-line ConditionalExpression,ArrayDeclaration: defensive guard against
  // null/undefined image fields in untrusted JSON-LD. Equivalent under the downstream filter in
  // buildImages (typeof === "string" + HTTP_RE), which discards any null/sentinel that leaks past.
  if (image == null) return [];
  return Array.isArray(image)
    ? (image as readonly string[])
    : [image as string];
};

const MAX_IMAGES = 8;
const HTTP_RE = /^https?:\/\//;

const buildImages = (raw: RawProductPage): readonly string[] => {
  const product = raw.jsonLdProducts[0];
  const candidates = [...toImageArray(product?.image), ...raw.ogImages];
  const seen = new Set<string>();
  const result: string[] = [];
  for (const url of candidates) {
    if (
      // Stryker disable next-line ConditionalExpression: runtime guard against non-string image
      // entries in untrusted JSON-LD. Equivalent under the static string[] type, but real defense.
      typeof url === "string" &&
      HTTP_RE.test(url) &&
      // Never offer a candidate the import action is guaranteed to reject (e.g. .svg logos
      // JSON-LD/OG frequently carry). Extension-less URLs pass — the action stays authoritative.
      !hasUnsupportedImageExtension(url) &&
      !seen.has(url) &&
      result.length < MAX_IMAGES
    ) {
      seen.add(url);
      result.push(url);
    }
  }
  return result;
};

// Keep only the alt entries whose image survived dedup/cap, so the draft never references a URL
// that isn't in `images`. Returns undefined (not {}) when nothing matches, keeping the draft minimal.
const pickAlts = (
  images: readonly string[],
  alts: Readonly<Record<string, string>> | undefined,
): Readonly<Record<string, string>> | undefined => {
  if (!alts) return undefined;
  const out: Record<string, string> = {};
  for (const url of images) {
    const alt = alts[url];
    if (alt) out[url] = alt;
  }
  return Object.keys(out).length > 0 ? out : undefined;
};

const barcodes = (
  product: JsonLdProduct | undefined,
): { ean?: string; upc?: string } => {
  const gtin13 =
    product?.gtin13 ??
    (product?.gtin?.length === 13 ? product.gtin : undefined);
  const gtin12 =
    product?.gtin12 ??
    (product?.gtin?.length === 12 ? product.gtin : undefined);
  return { ean: gtin13, upc: gtin12 };
};

const clean = (value: string | undefined): string | undefined => {
  const trimmed = value?.trim();
  return trimmed ? trimmed : undefined;
};

// Tiered, in order: JSON-LD Product -> OpenGraph -> <title>/<meta>. Piece count regex runs over
// title + description. Title is "" when no tier yields one; the caller decides if that is usable.
export const extractPuzzleDraft = (
  raw: RawProductPage,
  sourceUrl: string,
): PuzzleImportDraft => {
  const product = raw.jsonLdProducts[0];
  // Compute rawTitle BEFORE cleaning — pieceCount is parsed from it. No outer trim is needed:
  // parsePieceCount tolerates surrounding whitespace and cleanPuzzleTitle trims internally.
  const rawTitle = product?.name ?? raw.ogTitle ?? raw.basicTitle ?? "";
  const description = clean(
    product?.description ?? raw.ogDescription ?? raw.basicDescription,
  );
  const { ean, upc } = barcodes(product);
  const brand = clean(product?.brand);
  // Parse piece count from the ORIGINAL title + description so cleaning doesn't lose the count.
  // Stryker disable next-line StringLiteral: the "" fallback only applies when description is
  // absent; any replacement string is whitespace/word-only and carries no digit+unit token, so it
  // cannot change the parsed piece count — an equivalent mutant.
  const pieceCount = parsePieceCount(`${rawTitle} ${description ?? ""}`);
  // Clean title AFTER deriving pieceCount (cleaning may strip the count phrase).
  const title = cleanPuzzleTitle(rawTitle);

  // Build deduplicated image list: JSON-LD product images first, then OG images.
  const images = buildImages(raw);

  return {
    title,
    brand,
    imageUrl: images[0],
    images,
    imageAlts: pickAlts(images, raw.imageAlts),
    description,
    ean,
    upc,
    pieceCount,
    sourceUrl,
  };
};

src/catalog/application/make-fallback-st.source:
import { ok } from "../../shared-kernel";
import {
  type RawProductPage,
  type StorePageFetchError,
  type StorePageFetchErrorCode,
} from "../domain";
import { type StorePageFetcher } from "./ports/out/store-page-fetcher";

// Error codes worth retrying with a different fetch strategy (blocked/garbled/missing pages).
// Not retried: InvalidUrl (won't change), Timeout (already slow — don't double the wait).
const RETRYABLE: ReadonlyArray<StorePageFetchErrorCode> = [
  "Blocked",
  "NotFound",
  "FetchFailed",
  "Unparseable",
];

// Every image URL a fetched page surfaced: each JSON-LD product's image(s) plus the OpenGraph
// images. Used to decide whether a page is "image-complete" and to merge a later tier's images in.
const imagesOf = (page: RawProductPage): string[] => {
  const out: string[] = [];
  for (const product of page.jsonLdProducts) {
    if (typeof product.image === "string") out.push(product.image);
    else if (Array.isArray(product.image)) out.push(...product.image);
  }
  out.push(...page.ogImages);
  return out;
};

// True when the page surfaced at least one (non-empty) image candidate. A page with a title but NO
// image is common when a tier reads only structured data — a later tier that scrapes the raw HTML
// may still find the image, so it's worth trying the fallback even on an otherwise-OK page.
const hasImages = (page: RawProductPage): boolean =>
  imagesOf(page).some((url) => url.length > 0);

// Gap-filling merge: keep the primary's fields where present, fill a missing title/description from
// the fallback, and ADD the fallback's images to the primary's OpenGraph images. Lets a tier that
// found the title but no image be completed by a later tier that found the image, without losing the
// primary's data. (The primary's JSON-LD products are preserved, so their own images stay attached.)
const mergePages = (
  primary: RawProductPage,
  fallback: RawProductPage,
): RawProductPage => {
  // Union the per-URL alt maps; the primary wins on a key conflict. Undefined (not {}) when neither
  // tier scraped alt text, keeping the merged page minimal.
  const mergedAlts = { ...fallback.imageAlts, ...primary.imageAlts };
  return {
    ogTitle: primary.ogTitle ?? fallback.ogTitle,
    ogDescription: primary.ogDescription ?? fallback.ogDescription,
    basicTitle: primary.basicTitle ?? fallback.basicTitle,
    basicDescription: primary.basicDescription ?? fallback.basicDescription,
    ogImages: [...primary.ogImages, ...imagesOf(fallback)],
    imageAlts: Object.keys(mergedAlts).length > 0 ? mergedAlts : undefined,
    jsonLdProducts:
      primary.jsonLdProducts.length > 0
        ? primary.jsonLdProducts
        : fallback.jsonLdProducts,
    source:
      primary.source != null && fallback.source != null
        ? `${primary.source}+${fallback.source}`
        : (primary.source ?? fallback.source),
  };
};

// Tries `primary`; if it fails with a retryable error, tries `fallback`. Additionally, when the
// primary SUCCEEDS but the page carries no image, it tries the fallback too and merges any images it
// finds into the primary's result (a tier may read the title from structured data yet miss an image
// only present in the raw HTML). Returns the merged page on success, else the primary's result.
export const makeFallbackStorePageFetcher = (
  primary: StorePageFetcher,
  fallback: StorePageFetcher,
  shouldFallback: (e: StorePageFetchError) => boolean = (e) =>
    RETRYABLE.includes(e.code),
): StorePageFetcher => ({
  async fetch(url) {
    const first = await primary.fetch(url);
    if (first.isErr) {
      return shouldFallback(first.error) ? fallback.fetch(url) : first;
    }
    // OK and already has an image: nothing more to gain from another fetch.
    if (hasImages(first.value)) return first;
    // OK but image-less: a different tier might surface the image — merge it in if so.
    const second = await fallback.fetch(url);
    return second.isOk ? ok(mergePages(first.value, second.value)) : first;
  },
});

