import {
  Clock,
  DomainEvent,
  DomainEventPublisher,
  ok,
  Result,
} from "../../../shared-kernel";
import {
  MarkAllRead,
  MarkAllReadCommand,
} from "../ports/in/mark-all-read.port";
import { NotificationRepository } from "../ports/out/notification.repository";

export interface MarkAllReadDeps {
  readonly notifications: NotificationRepository;
  readonly events: DomainEventPublisher;
  readonly clock: Clock;
}

// Bulk-mark a member's unread notifications. The repository returns the affected aggregates with
// their NotificationRead events already recorded (markAllReadForUser only touches unread ones);
// we drain and publish those events and report the count. No ownership check is needed because the
// scan is scoped to the member by construction.
export const makeMarkAllRead =
  (deps: MarkAllReadDeps): MarkAllRead =>
  async (cmd: MarkAllReadCommand): Promise<Result<number, never>> => {
    const affected = await deps.notifications.markAllReadForUser(
      cmd.memberId,
      deps.clock.now(),
    );

    const pending: DomainEvent[] = [];
    for (const notification of affected) {
      pending.push(...notification.pullEvents());
    }
    if (pending.length > 0) {
      await deps.events.publish(pending);
    }
    return ok(affected.length);
  };

import {
  Clock,
  DomainEventPublisher,
  err,
  ok,
  Result,
} from "../../../shared-kernel";
import { NotificationError } from "../../domain";
import { NotificationApplicationError } from "../errors";
import {
  MarkNotificationRead,
  MarkNotificationReadCommand,
} from "../ports/in/mark-notification-read.port";
import { NotificationRepository } from "../ports/out/notification.repository";

export interface MarkNotificationReadDeps {
  readonly notifications: NotificationRepository;
  readonly events: DomainEventPublisher;
  readonly clock: Clock;
}

// Load the notification, delegate the ownership + idempotency rules to the aggregate, then save
// and publish. A missing notification is an application error; a wrong owner is a domain error.
export const makeMarkNotificationRead =
  (deps: MarkNotificationReadDeps): MarkNotificationRead =>
  async (
    cmd: MarkNotificationReadCommand,
  ): Promise<
    Result<void, NotificationError | NotificationApplicationError>
  > => {
    const notification = await deps.notifications.findById(cmd.notificationId);
    if (!notification) {
      return err(
        NotificationApplicationError.notificationNotFound(cmd.notificationId),
      );
    }

    const marked = notification.markRead(cmd.memberId, deps.clock.now());
    if (marked.isErr) return err(marked.error);

    await deps.notifications.save(notification);
    await deps.events.publish(notification.pullEvents());
    return ok(undefined);
  };

import {
  Clock,
  DomainEvent,
  DomainEventPublisher,
  ok,
  Result,
} from "../../../shared-kernel";
import {
  Channel,
  CHANNELS,
  MemberId,
  Notification,
  NotificationId,
  NotificationPreference,
} from "../../domain";
import {
  NotifyMember,
  NotifyMemberCommand,
} from "../ports/in/notify-member.port";
import { NotificationDelivery } from "../ports/out/notification-delivery.port";
import { NotificationIdGenerator } from "../ports/out/notification-id-generator";
import { NotificationPreferenceIdGenerator } from "../ports/out/notification-preference-id-generator";
import { NotificationPreferenceRepository } from "../ports/out/notification-preference.repository";

export interface NotifyMemberDeps {
  readonly delivery: NotificationDelivery;
  readonly preferences: NotificationPreferenceRepository;
  readonly notificationIds: NotificationIdGenerator;
  readonly preferenceIds: NotificationPreferenceIdGenerator;
  readonly events: DomainEventPublisher;
  readonly clock: Clock;
}

// The key entry the backend subscriber calls. This is the POLICY SEAM that makes Notifications a
// pure subscriber: it loads the member's preference (or a default if none stored), then for each
// candidate channel allowed by that preference, creates and saves a Notification. If the member
// has suppressed every channel for this type, it is a legitimate no-op (ok with an empty array).
//
// Notifications never fails here — there is no upstream contract to break; an unwanted event is
// simply not materialised. Hence the `never` error channel.
export const makeNotifyMember =
  (deps: NotifyMemberDeps): NotifyMember =>
  async (
    cmd: NotifyMemberCommand,
  ): Promise<Result<readonly NotificationId[], never>> => {
    const preference = await loadPreference(deps, cmd.memberId);

    const candidates: readonly Channel[] = cmd.channels ?? CHANNELS;
    const allowed = candidates.filter((channel) =>
      preference.allows(cmd.type, channel),
    );

    const created: NotificationId[] = [];
    const pending: DomainEvent[] = [];
    const now = deps.clock.now();

    for (const channel of allowed) {
      const notification = Notification.create({
        id: deps.notificationIds.next(),
        userId: cmd.memberId,
        type: cmd.type,
        title: cmd.title,
        message: cmd.message,
        relatedId: cmd.relatedId,
        channel,
        now,
      });
      // Delivery owns the medium: in-app persists, email/push dispatch out-of-band. The use case
      // stays oblivious to which, and must NOT also persist or in-app rows would double-write.
      await deps.delivery.deliver(channel, notification);
      created.push(notification.id);
      pending.push(...notification.pullEvents());
    }

    if (pending.length > 0) {
      await deps.events.publish(pending);
    }
    return ok(created);
  };

// Load the member's stored preference, or materialise (and persist) the sensible default so a
// member who never visited their settings still receives the default in-app deliveries.
const loadPreference = async (
  deps: NotifyMemberDeps,
  memberId: MemberId,
): Promise<NotificationPreference> => {
  const existing = await deps.preferences.findByMember(memberId);
  if (existing) return existing;

  const fresh = NotificationPreference.createDefault(
    deps.preferenceIds.next(),
    memberId,
    deps.clock.now(),
  );
  await deps.preferences.save(fresh);
  return fresh;
};

import {
  Clock,
  DomainEventPublisher,
  ok,
  Result,
} from "../../../shared-kernel";
import { NotificationPreference } from "../../domain";
import {
  UpdateNotificationPreference,
  UpdateNotificationPreferenceCommand,
} from "../ports/in/update-notification-preference.port";
import { NotificationPreferenceIdGenerator } from "../ports/out/notification-preference-id-generator";
import { NotificationPreferenceRepository } from "../ports/out/notification-preference.repository";

export interface UpdateNotificationPreferenceDeps {
  readonly preferences: NotificationPreferenceRepository;
  readonly preferenceIds: NotificationPreferenceIdGenerator;
  readonly events: DomainEventPublisher;
  readonly clock: Clock;
}

// Toggle a single (type, channel) for a member, materialising the default preference first if the
// member has none stored. Delegates enablement (and the no-op-when-unchanged rule) to the
// aggregate, then saves and publishes any PreferenceChanged event.
export const makeUpdateNotificationPreference =
  (deps: UpdateNotificationPreferenceDeps): UpdateNotificationPreference =>
  async (
    cmd: UpdateNotificationPreferenceCommand,
  ): Promise<Result<void, never>> => {
    const now = deps.clock.now();
    const preference =
      (await deps.preferences.findByMember(cmd.memberId)) ??
      NotificationPreference.createDefault(
        deps.preferenceIds.next(),
        cmd.memberId,
        now,
      );

    if (cmd.enabled) {
      preference.enable(cmd.type, cmd.channel, now);
    } else {
      preference.disable(cmd.type, cmd.channel, now);
    }

    await deps.preferences.save(preference);
    await deps.events.publish(preference.pullEvents());
    return ok(undefined);
  };

