import { MemberId, MembershipId } from "./ids";
import { PermissionLevel } from "./permission-level";

// The persistable shape of a single membership row within a Circle. A child entity of the Circle
// aggregate: it has its own identity (MembershipId) but is only ever reached through its Circle,
// which guards every change so the invariants hold.
export interface MembershipState {
  readonly id: MembershipId;
  readonly memberId: MemberId;
  readonly permission: PermissionLevel;
  readonly joinedAt: Date;
}

// Membership: a member's seat in a circle at a given permission. Immutable; the aggregate replaces
// the whole row (via withPermission) rather than mutating in place, so events stay the only signal
// of change.
export class Membership {
  private constructor(private readonly state: MembershipState) {}

  get id(): MembershipId {
    return this.state.id;
  }

  get memberId(): MemberId {
    return this.state.memberId;
  }

  get permission(): PermissionLevel {
    return this.state.permission;
  }

  get joinedAt(): Date {
    return this.state.joinedAt;
  }

  static create(
    id: MembershipId,
    memberId: MemberId,
    permission: PermissionLevel,
    joinedAt: Date,
  ): Membership {
    return new Membership({ id, memberId, permission, joinedAt });
  }

  // A copy of this membership at a new permission level, preserving identity and join time.
  withPermission(permission: PermissionLevel): Membership {
    return new Membership({ ...this.state, permission });
  }

  static rehydrate(state: MembershipState): Membership {
    return new Membership(state);
  }

  toState(): MembershipState {
    return this.state;
  }
}

src/sharing/domain/permission-level.ts.source:
// What a member is allowed to do within a Circle. A literal union (not a class) because it is a
// plain enumerated capability the boundary passes as a primitive. `ViewOnly` may see circle
// content; `Exchange` may additionally transact within the circle; `Admin` may additionally
// manage membership and permissions. The owner is implicitly `Admin`.
export type PermissionLevel = "ViewOnly" | "Exchange" | "Admin";

// Ordering used for capability checks: a higher rank subsumes the lower ones.
const RANK: Readonly<Record<PermissionLevel, number>> = {
  ViewOnly: 0,
  Exchange: 1,
  Admin: 2,
};

// Admin is the only level that may manage membership/permissions (owner is implicitly Admin).
export const canManageMembers = (level: PermissionLevel): boolean =>
  level === "Admin";

// Exchange and Admin may transact within the circle; ViewOnly may not.
export const canExchangeWithin = (level: PermissionLevel): boolean =>
  RANK[level] >= RANK.Exchange;

src/sharing/domain/visibility-policy.ts.source:
import { CircleId, MemberId } from "./ids";
import {
  isPubliclyViewable,
  permitsTransaction,
  TransactionKind,
  VisibilityScope,
} from "./visibility-scope";

// VisibilityPolicy: the pure, circle-aware decision that unifies the 6-level model. It is a DOMAIN
// SERVICE — it loads nothing. The caller resolves the relevant circle-membership facts (which
// circles the viewer and owner BOTH belong to) and passes them in as `sharedCircles`, so the
// policy stays a total function of its inputs and free of I/O. The two questions it answers:
//
//   canView      — may `viewer` see content owned by `ownerId` at the given `scope`?
//   canTransact  — may `viewer` transact (`kind`) on that content?
//
// Semantics by scope:
//   private      → only the owner (view); nobody else, and no transaction.
//   friendCircle → viewer must share at least one circle with the owner (view); no public transact.
//   visible      → public view; no transaction.
//   lendable/swappable/tradeable → public view; transaction allowed when `kind` matches the scope.
//
// The owner can always see and transact their own content, regardless of scope.
export const VisibilityPolicy = {
  // `sharedCircles` is the set of circles the viewer and owner are BOTH members of (already
  // intersected by the caller). Its emptiness is the only friend-circle fact the policy needs.
  canView(
    viewer: MemberId,
    ownerId: MemberId,
    scope: VisibilityScope,
    sharedCircles: readonly CircleId[],
  ): boolean {
    if (viewer === ownerId) return true;
    if (scope === "private") return false;
    if (scope === "friendCircle") return sharedCircles.length > 0;
    return isPubliclyViewable(scope);
  },

  canTransact(
    viewer: MemberId,
    ownerId: MemberId,
    scope: VisibilityScope,
    sharedCircles: readonly CircleId[],
    kind: TransactionKind,
  ): boolean {
    if (viewer === ownerId) return true;
    // A transaction always presupposes the right to view; private/friendCircle/visible never
    // grant a public transaction (a friendCircle copy is shareable, not tradeable, by this policy).
    if (!this.canView(viewer, ownerId, scope, sharedCircles)) return false;
    return permitsTransaction(scope, kind);
  },
};

src/sharing/domain/visibility-scope.ts.source:
// The unified 6-level visibility model (§1.4) a copy/collection owner attaches to their content.
// Modelled as a literal union with capability helpers rather than a pile of booleans on a row —
// "sharing is a policy, not a pile of flags" (§1.1). The levels, low → high openness:
//
//   private      → only the owner sees it; nobody transacts.
//   friendCircle → only members who share a circle with the owner may see it.
//   visible      → anyone may see it, but nobody may transact (a public showcase).
//   lendable     → publicly visible; may be borrowed (Lend).
//   swappable    → publicly visible; may be swapped (Swap).
//   tradeable    → publicly visible; may be traded/sold (Trade).
export type VisibilityScope =
  | "private"
  | "friendCircle"
  | "visible"
  | "lendable"
  | "swappable"
  | "tradeable";

// The kind of transaction a viewer wants to perform. Mirrors Exchange's kinds; passed as a
// primitive so the policy can gate the higher scopes by transaction kind without importing
// Exchange. `view` is folded into canView, so this union covers only the transacting verbs.
export type TransactionKind = "lend" | "swap" | "trade";

// Scopes that grant a PUBLIC view (no circle membership required). friendCircle and private are
// deliberately absent — they are gated separately by the policy.
const PUBLICLY_VIEWABLE: ReadonlySet<VisibilityScope> = new Set([
  "visible",
  "lendable",
  "swappable",
  "tradeable",
]);

// Which transaction kind each transactable scope permits. `visible` permits viewing but no
// transaction, so it (and the non-public scopes) are absent.
const TRANSACTABLE: Readonly<
  Partial<Record<VisibilityScope, TransactionKind>>
> = {
  lendable: "lend",
  swappable: "swap",
  tradeable: "trade",
};

// True for any scope that lets a non-owner, non-circle viewer see the content.
export const isPubliclyViewable = (scope: VisibilityScope): boolean =>
  PUBLICLY_VIEWABLE.has(scope);

// True iff the scope permits the given transaction kind for anyone allowed to transact. `visible`
// and the non-public scopes never permit a transaction.
export const permitsTransaction = (
  scope: VisibilityScope,
  kind: TransactionKind,
): boolean => TRANSACTABLE[scope] === kind;

