import { Clock, DomainEventPublisher, err, ok } from "../../../shared-kernel";
import { SolvingError } from "../../domain";
import { SolvingApplicationError } from "../errors";
import {
  FinishCompletion,
  FinishCompletionCommand,
} from "../ports/in/finish-completion.port";
