import { err, ok, Result } from "../../shared-kernel";
import { SolvingError } from "./errors";

const MS_PER_MINUTE = 60_000;

// A solve duration measured in whole positive minutes (mirrors the persisted
// `completions.completionTimeMinutes`). A value object so the "positive minutes" invariant
// lives in one place and a Completion never holds a negative or fractional duration.
export class SolveDuration {
  private constructor(readonly minutes: number) {}

  static ofMinutes(minutes: number): Result<SolveDuration, SolvingError> {
    if (!Number.isFinite(minutes) || minutes <= 0) {
      return err(SolvingError.invalidDuration());
    }
    return ok(new SolveDuration(Math.round(minutes)));
  }

  // Derive a duration from a start/end pair (end must be on or after start). A zero-length span
  // is not a valid solve, so equal instants are rejected as an invalid duration.
  static between(start: Date, end: Date): Result<SolveDuration, SolvingError> {
    const ms = end.getTime() - start.getTime();
    if (ms <= 0) return err(SolvingError.invalidDuration());
    return SolveDuration.ofMinutes(ms / MS_PER_MINUTE);
  }

  // Rehydrate a persisted value that was already validated when first stored.
  static fromState(minutes: number): SolveDuration {
    return new SolveDuration(minutes);
  }

  equals(other: SolveDuration): boolean {
    return this.minutes === other.minutes;
  }
}

src/solving/domain/solving-preferences.t.source:
import { MemberId } from "./ids";

// A member's Solving-context preferences. Identified by memberId (one per member). Eventless:
// settings carry no domain events that other contexts react to. `trackCompletionDuration`
// undefined means the member has never chosen — the UI uses that to drive the first-time prompt.
export interface SolvingPreferencesState {
  readonly memberId: MemberId;
  readonly trackCompletionDuration?: boolean;
  readonly updatedAt: Date;
}

export class SolvingPreferences {
  private constructor(private state: SolvingPreferencesState) {}

  get memberId(): MemberId {
    return this.state.memberId;
  }

  get trackCompletionDuration(): boolean | undefined {
    return this.state.trackCompletionDuration;
  }

  static createDefault(memberId: MemberId, now: Date): SolvingPreferences {
    return new SolvingPreferences({
      memberId,
      trackCompletionDuration: undefined,
      updatedAt: now,
    });
  }

  setTrackCompletionDuration(enabled: boolean, now: Date): void {
    if (this.state.trackCompletionDuration === enabled) return;
    this.state = {
      ...this.state,
      trackCompletionDuration: enabled,
      updatedAt: now,
    };
  }

  static rehydrate(state: SolvingPreferencesState): SolvingPreferences {
    return new SolvingPreferences(state);
  }

  toState(): SolvingPreferencesState {
    return this.state;
  }
}

src/solving/domain/star-rating.ts.source:
import { err, ok, Result } from "../../shared-kernel";
import { SolvingError } from "./errors";

// The lowest and highest stars a member may award a puzzle.
const MIN_STARS = 1;
const MAX_STARS = 5;

// A 1–5 star rating value object, reused by PuzzleReview. A rating is the member's opinion of
// the PUZZLE (difficulty/quality), not of a trading partner — see the §1.5 homonym table.
export class StarRating {
  private constructor(readonly value: number) {}

  static create(value: number): Result<StarRating, SolvingError> {
    if (!Number.isInteger(value) || value < MIN_STARS || value > MAX_STARS) {
      return err(SolvingError.invalidRating(value));
    }
    return ok(new StarRating(value));
  }

  // Rehydrate a persisted value that was already validated when first stored.
  static fromState(value: number): StarRating {
    return new StarRating(value);
  }

  equals(other: StarRating): boolean {
    return this.value === other.value;
  }
}

