// Moderation lifecycle of a PuzzleDefinition. Only `approved` definitions are publicly
// listable (an application-layer query concern); the aggregate owns the transitions.
export type ApprovalStatus = "pending" | "approved" | "rejected" | "disabled";

// Legal approval moves. A submission starts `pending`; moderation decides it once. An
// approved definition may be reversibly disabled (hidden from public surfaces) and
// re-enabled; `rejected` stays terminal (re-submission would be a new definition).
export const ALLOWED_APPROVAL_TRANSITIONS: Readonly<
  Record<ApprovalStatus, readonly ApprovalStatus[]>
> = {
  pending: ["approved", "rejected"],
  approved: ["disabled"],
  disabled: ["approved"],
  rejected: [],
};

src/catalog/domain/proposal-status.ts.source:
// Lifecycle of a PuzzleChangeProposal. A member files it `pending`; an admin decides it once
// (approved/rejected) or the proposer withdraws it. All non-pending states are terminal —
// a member who wants to try again files a NEW proposal.
export type ProposalStatus = "pending" | "approved" | "rejected" | "withdrawn";

export const ALLOWED_PROPOSAL_TRANSITIONS: Readonly<
  Record<ProposalStatus, readonly ProposalStatus[]>
> = {
  pending: ["approved", "rejected", "withdrawn"],
  approved: [],
  rejected: [],
  withdrawn: [],
};

src/exchange/domain/exchange-kind.ts.source:
// The ubiquitous language of the Exchange context. Each kind carries a distinct
// term requirement (see terms.ts):
//   - swap: puzzle-for-puzzle; the initiator must offer one of their own copies.
//   - sale: money changes hands; a price is required.
//   - lend: temporary transfer; a return date is required.
export type ExchangeKind = "swap" | "sale" | "lend";

// Legacy persisted mapping (the `exchanges.type` column uses the older vocabulary).
// The 1b adapter/mapper translates between these; the domain only speaks the new terms.
//   swap <-> "trade"
//   sale <-> "sale"
//   lend <-> "loan"
export type LegacyExchangeKind = "trade" | "sale" | "loan";

export const EXCHANGE_KINDS: readonly ExchangeKind[] = ["swap", "sale", "lend"];

src/library/domain/condition.ts.source:
// The grading of a physical Copy, matching the persisted `ownedPuzzles.condition` column
// 1:1 (no legacy translation needed). Ordered best→worst so a future condition timeline can
// reason about deterioration.
//   new_sealed -> factory sealed, never opened
//   like_new   -> opened but perfect
//   good / fair / poor -> increasing wear
export type Condition = "new_sealed" | "like_new" | "good" | "fair" | "poor";

export const CONDITIONS: readonly Condition[] = [
  "new_sealed",
  "like_new",
  "good",
  "fair",
  "poor",
];

export const isCondition = (value: string): value is Condition =>
  (CONDITIONS as readonly string[]).includes(value);

