src/catalog/application/use-cases/change.source:
import { beforeEach, describe, expect, it } from "vitest";
import {
  toChangeProposalId,
  toPuzzleDefinitionId,
  toSubmitterId,
} from "../../../shared-kernel";
import { PuzzleChangeProposal, PuzzleDefinition } from "../../domain";
import {
  FixedClock,
  InMemoryChangeProposalRepository,
  InMemoryPuzzleDefinitionRepository,
  RecordingEventPublisher,
  SequentialIdGenerator,
} from "../testing";
import { makeApproveChangeProposal } from "./approve-change-proposal";
import { makeEditChangeProposal } from "./edit-change-proposal";
import { makeFileChangeProposal } from "./file-change-proposal";
import { makeRejectChangeProposal } from "./reject-change-proposal";
import { makeWithdrawChangeProposal } from "./withdraw-change-proposal";

const NOW = new Date("2026-07-08T10:00:00Z");
const alice = toSubmitterId("alice");
const bob = toSubmitterId("bob");

// Shared world for every proposal use-case spec: repositories + one approved definition.
const definitionId = toPuzzleDefinitionId("pd-existing");

let definitions: InMemoryPuzzleDefinitionRepository;
let proposals: InMemoryChangeProposalRepository;
let events: RecordingEventPublisher;
let clock: FixedClock;
let ids: SequentialIdGenerator;

const seedDefinition = async (status: "pending" | "approved" = "approved") => {
  const r = PuzzleDefinition.submit({
    id: definitionId,
    title: "Starry Night",
    pieceCount: 1000,
    submittedBy: bob,
    now: NOW,
  });
  if (!r.isOk) throw new Error("seed failed");
  if (status === "approved") {
    const approved = r.value.approve(NOW);
    if (approved.isErr) throw new Error("seed approve failed");
  }
  r.value.pullEvents();
  await definitions.save(r.value);
};

const deps = () => ({ proposals, definitions, ids, events, clock });

beforeEach(() => {
  definitions = new InMemoryPuzzleDefinitionRepository();
  proposals = new InMemoryChangeProposalRepository();
  events = new RecordingEventPublisher();
  clock = new FixedClock(NOW);
  ids = new SequentialIdGenerator();
});

describe("makeFileChangeProposal", () => {
  it("files a pending proposal with a server-derived baseline and publishes ChangeProposalFiled", async () => {
    await seedDefinition();
    const file = makeFileChangeProposal(deps());

    const r = await file({
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      changes: { title: "Corrected", pieceCount: 500 },
      comment: "box says 500",
    });

    expect(r.isOk).toBe(true);
    if (!r.isOk) return;
    const saved = await proposals.findById(r.value);
    expect(saved).not.toBeNull();
    const state = saved!.toState();
    expect(state.status).toBe("pending");
    expect(state.changes).toEqual({ title: "Corrected", pieceCount: 500 });
    // Baseline snapshots the CURRENT values of exactly the changed fields.
    expect(state.baseline).toEqual({ title: "Starry Night", pieceCount: 1000 });
    expect(state.comment).toBe("box says 500");
    expect(events.names()).toEqual(["ChangeProposalFiled"]);
  });

  it("rejects a proposal against a missing definition", async () => {
    const file = makeFileChangeProposal(deps());
    const r = await file({
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      changes: { title: "X" },
    });
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("PuzzleDefinitionNotFound");
  });

  it("rejects a proposal against a non-approved definition", async () => {
    await seedDefinition("pending");
    const file = makeFileChangeProposal(deps());
    const r = await file({
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      changes: { title: "X" },
    });
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("DefinitionNotProposable");
  });

  it("enforces one OPEN proposal per (definition, proposer)", async () => {
    await seedDefinition();
    const file = makeFileChangeProposal(deps());
    const first = await file({
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      changes: { title: "X" },
    });
    expect(first.isOk).toBe(true);

    const second = await file({
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      changes: { brand: "Ravensburger" },
    });
    expect(second.isErr).toBe(true);
    if (second.isErr)
      expect(second.error.code).toBe("OpenProposalAlreadyExists");

    // A DIFFERENT member may file concurrently.
    const other = await file({
      puzzleDefinitionId: definitionId,
      proposedBy: bob,
      changes: { brand: "Ravensburger" },
    });
    expect(other.isOk).toBe(true);
  });

  it("propagates aggregate validation failures without saving", async () => {
    await seedDefinition();
    const file = makeFileChangeProposal(deps());
    const r = await file({
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      changes: {},
    });
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("EmptyProposal");
    expect(proposals.size()).toBe(0);
    expect(events.published).toEqual([]);
  });

  it("snapshots the grouped barcode baseline from the definition's flat fields", async () => {
    const r = PuzzleDefinition.submit({
      id: toPuzzleDefinitionId("pd-barcoded"),
      title: "Barcoded",
      pieceCount: 500,
      submittedBy: bob,
      now: NOW,
      barcodes: { ean: "4006381333931", modelNumber: "RV-1" },
    });
    if (!r.isOk) throw new Error("seed failed");
    r.value.approve(NOW);
    r.value.pullEvents();
    await definitions.save(r.value);

    const file = makeFileChangeProposal(deps());
    const filed = await file({
      puzzleDefinitionId: toPuzzleDefinitionId("pd-barcoded"),
      proposedBy: alice,
      changes: { barcodes: { ean: "4006381333931", upc: "036000291452" } },
    });

    expect(filed.isOk).toBe(true);
    if (!filed.isOk) return;
    const state = (await proposals.findById(filed.value))!.toState();
    expect(state.baseline).toEqual({
      barcodes: { ean: "4006381333931", upc: undefined, modelNumber: "RV-1" },
    });
  });
});

describe("makeEditChangeProposal", () => {
  it("replaces changes/comment and re-derives the baseline against the CURRENT definition", async () => {
    await seedDefinition();
    const file = makeFileChangeProposal(deps());
    const filed = await file({
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      changes: { title: "First idea" },
    });
    if (!filed.isOk) throw new Error("setup failed");
    events.published.length = 0;

    const edit = makeEditChangeProposal(deps());
    const r = await edit({
      changeProposalId: filed.value,
      changes: { pieceCount: 500 },
      comment: "recount",
    });

    expect(r.isOk).toBe(true);
    const state = (await proposals.findById(filed.value))!.toState();
    expect(state.changes).toEqual({ pieceCount: 500 });
    expect(state.baseline).toEqual({ pieceCount: 1000 });
    expect(state.comment).toBe("recount");
    expect(events.names()).toEqual(["ChangeProposalEdited"]);
  });

  it("fails with ChangeProposalNotFound for an unknown id", async () => {
    await seedDefinition();
    const edit = makeEditChangeProposal(deps());
    const r = await edit({
      changeProposalId: ids.nextChangeProposalId(),
      changes: { title: "X" },
    });
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("ChangeProposalNotFound");
  });

  it("propagates ProposalNotPending from the aggregate", async () => {
    await seedDefinition();
    const file = makeFileChangeProposal(deps());
    const filed = await file({
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      changes: { title: "X" },
    });
    if (!filed.isOk) throw new Error("setup failed");
    const withdraw = makeWithdrawChangeProposal(deps());
    await withdraw({ changeProposalId: filed.value });

    const edit = makeEditChangeProposal(deps());
    const r = await edit({
      changeProposalId: filed.value,
      changes: { title: "Y" },
    });
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("ProposalNotPending");
  });

  it("fails with PuzzleDefinitionNotFound when the target definition has disappeared", async () => {
    await seedDefinition();
    const file = makeFileChangeProposal(deps());
    const filed = await file({
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      changes: { title: "First idea" },
    });
    if (!filed.isOk) throw new Error("setup failed");
    // Sabotage: the definition disappears between filing and editing.
    definitions = new InMemoryPuzzleDefinitionRepository();

    const edit = makeEditChangeProposal(deps());
    const r = await edit({
      changeProposalId: filed.value,
      changes: { pieceCount: 500 },
    });
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("PuzzleDefinitionNotFound");
  });
});

describe("makeWithdrawChangeProposal", () => {
  it("moves a pending proposal to withdrawn and publishes ChangeProposalWithdrawn", async () => {
    await seedDefinition();
    const file = makeFileChangeProposal(deps());
    const filed = await file({
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      changes: { title: "X" },
    });
    if (!filed.isOk) throw new Error("setup failed");
    events.published.length = 0;

    const withdraw = makeWithdrawChangeProposal(deps());
    const r = await withdraw({ changeProposalId: filed.value });

    expect(r.isOk).toBe(true);
    expect((await proposals.findById(filed.value))!.status).toBe("withdrawn");
    expect(events.names()).toEqual(["ChangeProposalWithdrawn"]);
  });

  it("after withdrawing, the same member may file a fresh proposal", async () => {
    await seedDefinition();
    const file = makeFileChangeProposal(deps());
    const filed = await file({
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      changes: { title: "X" },
    });
    if (!filed.isOk) throw new Error("setup failed");
    const withdraw = makeWithdrawChangeProposal(deps());
    await withdraw({ changeProposalId: filed.value });

    const again = await file({
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      changes: { title: "Y" },
    });
    expect(again.isOk).toBe(true);
  });

  it("fails with ChangeProposalNotFound for an unknown id", async () => {
    const withdraw = makeWithdrawChangeProposal(deps());
    const r = await withdraw({ changeProposalId: ids.nextChangeProposalId() });
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("ChangeProposalNotFound");
  });

  it("cannot withdraw a proposal twice, and publishes nothing on the second attempt", async () => {
    await seedDefinition();
    const file = makeFileChangeProposal(deps());
    const filed = await file({
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      changes: { title: "X" },
    });
    if (!filed.isOk) throw new Error("setup failed");

    const withdraw = makeWithdrawChangeProposal(deps());
    await withdraw({ changeProposalId: filed.value });
    events.published.length = 0;

    const again = await withdraw({ changeProposalId: filed.value });
    expect(again.isErr).toBe(true);
    if (again.isErr) expect(again.error.code).toBe("IllegalProposalTransition");
    expect(events.published).toEqual([]);
  });
});

describe("makeApproveChangeProposal", () => {
  const fileOne = async (
    changes: Parameters<
      ReturnType<typeof makeFileChangeProposal>
    >[0]["changes"],
  ) => {
    const filed = await makeFileChangeProposal(deps())({
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      changes,
    });
    if (!filed.isOk) throw new Error("setup failed");
    events.published.length = 0;
    return filed.value;
  };

  it("approves the proposal AND applies the patch to the definition, publishing both batches", async () => {
    await seedDefinition();
    const proposalId = await fileOne({ title: "Corrected", pieceCount: 500 });

    const approve = makeApproveChangeProposal(deps());
    const r = await approve({ changeProposalId: proposalId });

    expect(r.isOk).toBe(true);
    const proposal = (await proposals.findById(proposalId))!;
    expect(proposal.status).toBe("approved");
    const definition = (await definitions.findById(definitionId))!.toState();
    expect(definition.title).toBe("Corrected");
    expect(definition.pieceCount).toBe(500);
    // Both aggregates' events land in one publish sequence: proposal first, then definition.
    expect(events.names()).toEqual([
      "ChangeProposalApproved",
      "PuzzleDefinitionUpdated",
    ]);
  });

  it("fails with ChangeProposalNotFound for an unknown id", async () => {
    await seedDefinition();
    const approve = makeApproveChangeProposal(deps());
    const r = await approve({ changeProposalId: ids.nextChangeProposalId() });
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("ChangeProposalNotFound");
  });

  it("cannot approve twice — and does not double-apply the patch", async () => {
    await seedDefinition();
    const proposalId = await fileOne({ title: "Corrected" });
    const approve = makeApproveChangeProposal(deps());
    await approve({ changeProposalId: proposalId });

    const again = await approve({ changeProposalId: proposalId });
    expect(again.isErr).toBe(true);
    if (again.isErr) expect(again.error.code).toBe("IllegalProposalTransition");
  });

  it("saves NOTHING when applying the patch fails on the definition", async () => {
    await seedDefinition();
    const proposalId = await fileOne({ title: "Corrected" });
    // Sabotage: the definition disappears between filing and approval.
    definitions = new InMemoryPuzzleDefinitionRepository();

    const approve = makeApproveChangeProposal(deps());
    const r = await approve({ changeProposalId: proposalId });

    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("PuzzleDefinitionNotFound");
    // The proposal is untouched (still pending) and nothing was published.
    expect((await proposals.findById(proposalId))!.status).toBe("pending");
    expect(events.published).toEqual([]);
  });

  it("saves NOTHING when the definition rejects the patch (invalid stored proposal)", async () => {
    await seedDefinition();
    // Bypass file()'s own validation to get an invalid diff into storage — rehydrate a
    // proposal directly rather than going through PuzzleChangeProposal.file(), so
    // definition.update() is the one that fails, not the proposal aggregate.
    const badProposal = PuzzleChangeProposal.rehydrate({
      id: toChangeProposalId("cp-bad"),
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      status: "pending",
      changes: { title: "   " },
      baseline: {},
      createdAt: NOW,
      updatedAt: NOW,
    });
    await proposals.save(badProposal);

    const approve = makeApproveChangeProposal(deps());
    const r = await approve({ changeProposalId: badProposal.id });

    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("EmptyTitle");
    // The proposal is untouched (still pending), the definition untouched, nothing published.
    expect((await proposals.findById(badProposal.id))!.status).toBe("pending");
    expect((await definitions.findById(definitionId))!.toState().title).toBe(
      "Starry Night",
    );
    expect(events.published).toEqual([]);
  });
});

describe("makeRejectChangeProposal", () => {
  it("rejects with a reason, leaves the definition untouched, publishes ChangeProposalRejected", async () => {
    await seedDefinition();
    const filed = await makeFileChangeProposal(deps())({
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      changes: { title: "Wrong idea" },
    });
    if (!filed.isOk) throw new Error("setup failed");
    events.published.length = 0;

    const reject = makeRejectChangeProposal(deps());
    const r = await reject({
      changeProposalId: filed.value,
      reason: "title matches the box",
    });

    expect(r.isOk).toBe(true);
    const state = (await proposals.findById(filed.value))!.toState();
    expect(state.status).toBe("rejected");
    expect(state.rejectionReason).toBe("title matches the box");
    expect((await definitions.findById(definitionId))!.toState().title).toBe(
      "Starry Night",
    );
    expect(events.names()).toEqual(["ChangeProposalRejected"]);
  });

  it("fails with ChangeProposalNotFound for an unknown id", async () => {
    const reject = makeRejectChangeProposal(deps());
    const r = await reject({ changeProposalId: ids.nextChangeProposalId() });
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("ChangeProposalNotFound");
  });

  it("cannot reject an already-withdrawn proposal", async () => {
    await seedDefinition();
    const filed = await makeFileChangeProposal(deps())({
      puzzleDefinitionId: definitionId,
      proposedBy: alice,
      changes: { title: "Wrong idea" },
    });
    if (!filed.isOk) throw new Error("setup failed");
    const withdraw = makeWithdrawChangeProposal(deps());
    await withdraw({ changeProposalId: filed.value });

    const reject = makeRejectChangeProposal(deps());
    const r = await reject({ changeProposalId: filed.value });
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("IllegalProposalTransition");
  });
});

src/library/application/use-cases/copy-u.source:
import { beforeEach, describe, expect, it } from "vitest";
import {
  toCopyId,
  toFileId,
  toOwnerId,
  toPuzzleDefinitionId,
} from "../../../shared-kernel";
import { CatalogSnapshot, Copy, CopyId } from "../../domain";
import {
  FakeCatalogSnapshotProvider,
  FakeCopyReservationPort,
  FixedClock,
  InMemoryCopyRepository,
  RecordingEventPublisher,
  SequentialCopyIdGenerator,
} from "../testing";
import { makeAcquireCopy } from "./acquire-copy";
import { makeAddCopyImage } from "./add-copy-image";
import { makeChangeCopyCondition } from "./change-copy-condition";
import { makeDeleteCopy } from "./delete-copy";
import { makeSetCopyCover } from "./set-copy-cover";
import { makeTransferCopyOwnership } from "./transfer-copy-ownership";
import { makeUpdateCopyDetails } from "./update-copy-details";
import { makeUpdateCopySharing } from "./update-copy-sharing";

const alice = toOwnerId("alice");
const bob = toOwnerId("bob");
const definitionId = toPuzzleDefinitionId("def1");
const NOW = new Date("2026-06-08T10:00:00Z");

const snapshot = (): CatalogSnapshot =>
  CatalogSnapshot.create({
    puzzleDefinitionId: definitionId,
    title: "Owl",
    pieceCount: 500,
  });

describe("makeAcquireCopy", () => {
  let copies: InMemoryCopyRepository;
  let snapshots: FakeCatalogSnapshotProvider;
  let events: RecordingEventPublisher;

  const acquire = () =>
    makeAcquireCopy({
      copies,
      snapshots,
      ids: new SequentialCopyIdGenerator(),
      events,
      clock: new FixedClock(NOW),
    });

  beforeEach(() => {
    copies = new InMemoryCopyRepository();
    snapshots = new FakeCatalogSnapshotProvider();
    events = new RecordingEventPublisher();
  });

  it("fetches the snapshot, saves the copy, and publishes CopyAcquired", async () => {
    snapshots.seed(snapshot(), { status: "approved", submitterId: bob });
    const result = await acquire()({
      ownerId: alice,
      puzzleDefinitionId: definitionId,
      condition: "good",
    });
    expect(result.isOk).toBe(true);
    expect(copies.size()).toBe(1);
    expect(events.names()).toEqual(["CopyAcquired"]);
  });

  it("holds the fetched snapshot on the saved copy", async () => {
    snapshots.seed(snapshot(), { status: "approved", submitterId: bob });
    const result = await acquire()({
      ownerId: alice,
      puzzleDefinitionId: definitionId,
      condition: "good",
    });
    expect(result.isOk).toBe(true);
    if (result.isOk) {
      const saved = await copies.findById(result.value);
      expect(saved?.toState().snapshot.title).toBe("Owl");
    }
  });

  it("rejects when the Catalog has no definition for the id (PuzzleNotFound)", async () => {
    const result = await acquire()({
      ownerId: alice,
      puzzleDefinitionId: definitionId,
      condition: "good",
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("PuzzleNotFound");
    expect(events.published).toHaveLength(0);
  });

  it("lets a member acquire their OWN pending submission", async () => {
    snapshots.seed(snapshot(), { status: "pending", submitterId: alice });
    const result = await acquire()({
      ownerId: alice,
      puzzleDefinitionId: definitionId,
      condition: "good",
    });
    expect(result.isOk).toBe(true);
    expect(events.names()).toEqual(["CopyAcquired"]);
  });

  it("lets a member acquire their OWN rejected submission", async () => {
    snapshots.seed(snapshot(), { status: "rejected", submitterId: alice });
    const result = await acquire()({
      ownerId: alice,
      puzzleDefinitionId: definitionId,
      condition: "good",
    });
    expect(result.isOk).toBe(true);
    expect(events.names()).toEqual(["CopyAcquired"]);
  });

  it("refuses to acquire someone else's pending submission (PuzzleNotAcquirable)", async () => {
    snapshots.seed(snapshot(), { status: "pending", submitterId: bob });
    const result = await acquire()({
      ownerId: alice,
      puzzleDefinitionId: definitionId,
      condition: "good",
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("PuzzleNotAcquirable");
    expect(events.published).toHaveLength(0);
    expect(copies.size()).toBe(0);
  });

  it("refuses to acquire someone else's DISABLED definition (PuzzleNotAcquirable)", async () => {
    snapshots.seed(snapshot(), { status: "disabled", submitterId: bob });
    const result = await acquire()({
      ownerId: alice,
      puzzleDefinitionId: definitionId,
      condition: "good",
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("PuzzleNotAcquirable");
    expect(events.published).toHaveLength(0);
    expect(copies.size()).toBe(0);
  });

  // Existing carve-out preserved: like pending/rejected, the SUBMITTER may still log a copy
  // of their own disabled submission.
  it("lets a member acquire their OWN disabled submission", async () => {
    snapshots.seed(snapshot(), { status: "disabled", submitterId: alice });
    const result = await acquire()({
      ownerId: alice,
      puzzleDefinitionId: definitionId,
      condition: "good",
    });
    expect(result.isOk).toBe(true);
    expect(events.names()).toEqual(["CopyAcquired"]);
  });
});

describe("copy mutation use cases", () => {
  let copies: InMemoryCopyRepository;
  let reservations: FakeCopyReservationPort;
  let events: RecordingEventPublisher;
  let copyId: CopyId;

  beforeEach(async () => {
    copies = new InMemoryCopyRepository();
    reservations = new FakeCopyReservationPort();
    events = new RecordingEventPublisher();
    const acquired = Copy.acquire({
      id: toCopyId("copy-seed"),
      ownerId: alice,
      snapshot: snapshot(),
      condition: "good",
      now: NOW,
    });
    if (!acquired.isOk) throw new Error("setup");
    copyId = acquired.value.id;
    await copies.save(acquired.value);
  });

  describe("makeChangeCopyCondition", () => {
    const run = () =>
      makeChangeCopyCondition({ copies, events, clock: new FixedClock(NOW) });

    it("re-grades the owner's copy and publishes CopyConditionChanged", async () => {
      const result = await run()({
        actingMemberId: alice,
        copyId,
        condition: "fair",
      });
      expect(result.isOk).toBe(true);
      expect(events.names()).toEqual(["CopyConditionChanged"]);
    });

    it("rejects a non-owner", async () => {
      const result = await run()({
        actingMemberId: bob,
        copyId,
        condition: "fair",
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) {
        expect(result.error.code).toBe("NotOwner");
        expect(result.error.message).toBe(
          "Acting member may not change this copy's condition",
        );
      }
    });

    it("rejects an unknown copy", async () => {
      const result = await run()({
        actingMemberId: alice,
        copyId: toCopyId("ghost"),
        condition: "fair",
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CopyNotFound");
    });
  });

  describe("makeUpdateCopySharing", () => {
    const run = () =>
      makeUpdateCopySharing({
        copies,
        reservations,
        events,
        clock: new FixedClock(NOW),
      });

    it("updates sharing and publishes CopyMadeAvailable", async () => {
      const result = await run()({
        actingMemberId: alice,
        copyId,
        visibility: "visible",
        forTrade: true,
      });
      expect(result.isOk).toBe(true);
      expect(events.names()).toEqual(["CopyMadeAvailable"]);
    });

    it("rejects a non-owner", async () => {
      const result = await run()({
        actingMemberId: bob,
        copyId,
        visibility: "visible",
        forTrade: true,
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) {
        expect(result.error.code).toBe("NotOwner");
        expect(result.error.message).toBe(
          "Acting member may not update this copy's sharing",
        );
      }
    });

    it("rejects an unknown copy", async () => {
      const result = await run()({
        actingMemberId: alice,
        copyId: toCopyId("ghost"),
        visibility: "visible",
        forTrade: true,
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CopyNotFound");
    });

    it("does not consult the reservation seam when withdrawing availability", async () => {
      // A private (not-for-exchange) setting must short-circuit before isReserved(), so the
      // `&&` guard's first operand genuinely gates the reservation lookup.
      reservations.reserve(copyId);
      const result = await run()({
        actingMemberId: alice,
        copyId,
        visibility: "private",
      });
      expect(result.isOk).toBe(true);
    });

    it("refuses to make a reserved copy available (Exchange seam)", async () => {
      reservations.reserve(copyId);
      const result = await run()({
        actingMemberId: alice,
        copyId,
        visibility: "visible",
        forTrade: true,
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CopyReserved");
      expect(events.published).toHaveLength(0);
    });

    it("allows withdrawing availability even when reserved (not making available)", async () => {
      reservations.reserve(copyId);
      const result = await run()({
        actingMemberId: alice,
        copyId,
        visibility: "private",
      });
      expect(result.isOk).toBe(true);
      expect(events.names()).toEqual(["CopyMadeUnavailable"]);
    });
  });

  describe("makeAddCopyImage", () => {
    const run = () =>
      makeAddCopyImage({ copies, events, clock: new FixedClock(NOW) });

    it("adds an image to the owner's copy and publishes CopyImageAdded", async () => {
      const result = await run()({
        actingMemberId: alice,
        copyId,
        fileId: toFileId("file1"),
        tag: "box_front",
      });
      expect(result.isOk).toBe(true);
      expect(events.names()).toEqual(["CopyImageAdded"]);
    });

    it("rejects a non-owner", async () => {
      const result = await run()({
        actingMemberId: bob,
        copyId,
        fileId: toFileId("file1"),
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) {
        expect(result.error.code).toBe("NotOwner");
        expect(result.error.message).toBe(
          "Acting member may not add an image to this copy",
        );
      }
    });

    it("rejects an unknown copy", async () => {
      const result = await run()({
        actingMemberId: alice,
        copyId: toCopyId("ghost"),
        fileId: toFileId("file1"),
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CopyNotFound");
      expect(events.published).toHaveLength(0);
    });

    it("forwards the image metadata fields onto the copy", async () => {
      const takenAt = new Date("2026-01-01T00:00:00Z");
      const result = await run()({
        actingMemberId: alice,
        copyId,
        fileId: toFileId("file2"),
        title: "Front of box",
        description: "Pristine",
        tag: "box_front",
        takenAt,
      });
      expect(result.isOk).toBe(true);
      const saved = await copies.findById(copyId);
      const images = saved?.toState().images ?? [];
      expect(images).toHaveLength(1);
      expect(images[0]).toMatchObject({
        title: "Front of box",
        description: "Pristine",
        tag: "box_front",
        takenAt,
      });
    });
  });

  describe("makeSetCopyCover", () => {
    const run = () =>
      makeSetCopyCover({ copies, events, clock: new FixedClock(NOW) });

    it("sets the owner's copy cover and publishes CopyCoverChanged", async () => {
      const result = await run()({
        actingMemberId: alice,
        copyId,
        coverImageId: "img-1",
      });
      expect(result.isOk).toBe(true);
      expect(events.names()).toEqual(["CopyCoverChanged"]);
      const saved = await copies.findById(copyId);
      expect(saved?.toState().coverImageId).toBe("img-1");
    });

    it("clears the cover (null) and publishes CopyCoverChanged", async () => {
      await run()({ actingMemberId: alice, copyId, coverImageId: "img-1" });
      const result = await run()({
        actingMemberId: alice,
        copyId,
        coverImageId: null,
      });
      expect(result.isOk).toBe(true);
      // Two cover changes published; the second carries the cleared (null) selection.
      expect(events.names()).toEqual(["CopyCoverChanged", "CopyCoverChanged"]);
      const saved = await copies.findById(copyId);
      expect(saved?.toState().coverImageId).toBeUndefined();
    });

    it("rejects a non-owner", async () => {
      const result = await run()({
        actingMemberId: bob,
        copyId,
        coverImageId: "img-1",
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) {
        expect(result.error.code).toBe("NotOwner");
        expect(result.error.message).toBe(
          "Acting member may not change this copy's cover",
        );
      }
      expect(events.published).toHaveLength(0);
    });

    it("rejects an unknown copy", async () => {
      const result = await run()({
        actingMemberId: alice,
        copyId: toCopyId("ghost"),
        coverImageId: "img-1",
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CopyNotFound");
      expect(events.published).toHaveLength(0);
    });
  });

  describe("makeUpdateCopyDetails", () => {
    const run = () =>
      makeUpdateCopyDetails({ copies, events, clock: new FixedClock(NOW) });

    it("applies the fields to the owner's copy and publishes CopyDetailsUpdated", async () => {
      const result = await run()({
        actingMemberId: alice,
        copyId,
        missingPiecesCount: 3,
        notes: "corner piece missing",
      });
      expect(result.isOk).toBe(true);
      expect(events.names()).toEqual(["CopyDetailsUpdated"]);
      const saved = await copies.findById(copyId);
      expect(saved?.toState().missingPiecesCount).toBe(3);
      expect(saved?.toState().notes).toBe("corner piece missing");
    });

    it("rejects a non-owner", async () => {
      const result = await run()({
        actingMemberId: bob,
        copyId,
        notes: "hi",
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) {
        expect(result.error.code).toBe("NotOwner");
        expect(result.error.message).toBe(
          "Acting member may not update this copy's details",
        );
      }
    });

    it("rejects an unknown copy", async () => {
      const result = await run()({
        actingMemberId: alice,
        copyId: toCopyId("ghost"),
        notes: "hi",
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CopyNotFound");
    });
  });

  describe("makeDeleteCopy", () => {
    const run = () =>
      makeDeleteCopy({
        copies,
        reservations,
        events,
        clock: new FixedClock(NOW),
      });

    it("removes the owner's copy and publishes CopyDeleted", async () => {
      const result = await run()({ actingMemberId: alice, copyId });
      expect(result.isOk).toBe(true);
      expect(copies.size()).toBe(0);
      expect(events.names()).toEqual(["CopyDeleted"]);
    });

    it("rejects a non-owner", async () => {
      const result = await run()({ actingMemberId: bob, copyId });
      expect(result.isErr).toBe(true);
      if (result.isErr) {
        expect(result.error.code).toBe("NotOwner");
        expect(result.error.message).toBe(
          "Acting member may not delete this copy",
        );
      }
      expect(copies.size()).toBe(1);
    });

    it("rejects an unknown copy", async () => {
      const result = await run()({
        actingMemberId: alice,
        copyId: toCopyId("ghost"),
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CopyNotFound");
    });

    it("refuses to delete a copy reserved by an active exchange (Exchange seam)", async () => {
      reservations.reserve(copyId);
      const result = await run()({ actingMemberId: alice, copyId });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CopyReserved");
      expect(copies.size()).toBe(1);
      expect(events.published).toHaveLength(0);
    });
  });

  describe("makeTransferCopyOwnership", () => {
    const run = () =>
      makeTransferCopyOwnership({ copies, events, clock: new FixedClock(NOW) });

    it("reassigns the copy to the new owner and publishes CopyOwnershipTransferred", async () => {
      const result = await run()({ copyId, newOwner: bob });
      expect(result.isOk).toBe(true);
      expect(events.names()).toEqual(["CopyOwnershipTransferred"]);
      const saved = await copies.findById(copyId);
      expect(saved?.ownerId).toBe(bob);
    });

    it("rejects an unknown copy", async () => {
      const result = await run()({
        copyId: toCopyId("ghost"),
        newOwner: bob,
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CopyNotFound");
      expect(events.published).toHaveLength(0);
    });
  });
});

