import { beforeEach, describe, expect, it } from "vitest";
import { toCircleId, toCopyId, toMemberId } from "../../../shared-kernel";
import { CircleId } from "../../domain";
import {
  FixedClock,
  InMemoryCircleRepository,
  RecordingEventPublisher,
  SequentialCircleIdGenerator,
  SequentialMembershipIdGenerator,
} from "../testing";
import { makeAddMember } from "./add-member";
import { makeChangePermission } from "./change-permission";
import { makeCreateCircle } from "./create-circle";
import { makeRemoveMember } from "./remove-member";
import { makeShareCopyToCircle } from "./share-copy-to-circle";

const owner = toMemberId("owner");
const alice = toMemberId("alice");
const bob = toMemberId("bob");
const missingCircle = toCircleId("nope");
const copyId = toCopyId("copy-1");
const NOW = new Date("2026-06-08T10:00:00Z");

describe("Sharing circle use cases", () => {
  let circles: InMemoryCircleRepository;
  let membershipIds: SequentialMembershipIdGenerator;
  let events: RecordingEventPublisher;
  let clock: FixedClock;

  let createCircle: ReturnType<typeof makeCreateCircle>;
  let addMember: ReturnType<typeof makeAddMember>;
  let removeMember: ReturnType<typeof makeRemoveMember>;
  let changePermission: ReturnType<typeof makeChangePermission>;
  let shareCopy: ReturnType<typeof makeShareCopyToCircle>;

  beforeEach(() => {
    circles = new InMemoryCircleRepository();
    membershipIds = new SequentialMembershipIdGenerator();
    events = new RecordingEventPublisher();
    clock = new FixedClock(NOW);

    createCircle = makeCreateCircle({
      circles,
      circleIds: new SequentialCircleIdGenerator(),
      membershipIds,
      events,
      clock,
    });
    addMember = makeAddMember({ circles, membershipIds, events, clock });
    removeMember = makeRemoveMember({ circles, events });
    changePermission = makeChangePermission({ circles, events });
    shareCopy = makeShareCopyToCircle({ circles, events, clock });
  });

  // Helper: create a circle and return its id (creation never fails).
  const openCircle = async (): Promise<CircleId> => {
    const result = await createCircle({ ownerId: owner, name: "Family" });
    if (!result.isOk) throw new Error("setup: create failed");
    return result.value;
  };

  describe("makeCreateCircle", () => {
    it("creates a circle owned by the actor and publishes CircleCreated", async () => {
      const result = await createCircle({ ownerId: owner, name: "Family" });

      expect(result.isOk).toBe(true);
      expect(circles.size()).toBe(1);
      if (result.isOk) {
        const circle = await circles.findById(result.value);
        expect(circle?.ownerId).toBe(owner);
        expect(circle?.isMember(owner)).toBe(true);
      }
      expect(events.names()).toEqual(["CircleCreated"]);
    });
  });

  describe("makeAddMember", () => {
    it("adds a member by an admin and publishes MemberJoinedCircle", async () => {
      const circleId = await openCircle();
      events.published.length = 0;

      const result = await addMember({
        circleId,
        actorId: owner,
        memberId: alice,
        permission: "ViewOnly",
      });

      expect(result.isOk).toBe(true);
      expect((await circles.findById(circleId))?.isMember(alice)).toBe(true);
      expect(events.names()).toEqual(["MemberJoinedCircle"]);
    });

    it("returns CircleNotFound for an unknown circle", async () => {
      const result = await addMember({
        circleId: missingCircle,
        actorId: owner,
        memberId: alice,
        permission: "ViewOnly",
      });

      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CircleNotFound");
    });

    it("rejects a non-admin actor and writes nothing", async () => {
      const circleId = await openCircle();
      await addMember({
        circleId,
        actorId: owner,
        memberId: alice,
        permission: "ViewOnly",
      });
      events.published.length = 0;

      const result = await addMember({
        circleId,
        actorId: alice, // only ViewOnly
        memberId: bob,
        permission: "ViewOnly",
      });

      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("NotCircleAdmin");
      expect((await circles.findById(circleId))?.isMember(bob)).toBe(false);
      expect(events.published).toHaveLength(0);
    });

    it("rejects adding an existing member", async () => {
      const circleId = await openCircle();
      await addMember({
        circleId,
        actorId: owner,
        memberId: alice,
        permission: "ViewOnly",
      });

      const result = await addMember({
        circleId,
        actorId: owner,
        memberId: alice,
        permission: "Admin",
      });

      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("AlreadyMember");
    });
  });

  describe("makeRemoveMember", () => {
    it("removes a member by an admin", async () => {
      const circleId = await openCircle();
      await addMember({
        circleId,
        actorId: owner,
        memberId: alice,
        permission: "ViewOnly",
      });

      const result = await removeMember({
        circleId,
        actorId: owner,
        memberId: alice,
      });

      expect(result.isOk).toBe(true);
      expect((await circles.findById(circleId))?.isMember(alice)).toBe(false);
    });

    it("refuses to remove the owner", async () => {
      const circleId = await openCircle();

      const result = await removeMember({
        circleId,
        actorId: owner,
        memberId: owner,
      });

      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CannotRemoveOwner");
    });

    it("returns CircleNotFound for an unknown circle", async () => {
      const result = await removeMember({
        circleId: missingCircle,
        actorId: owner,
        memberId: alice,
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CircleNotFound");
    });
  });

  describe("makeChangePermission", () => {
    it("changes a member's permission by an admin", async () => {
      const circleId = await openCircle();
      await addMember({
        circleId,
        actorId: owner,
        memberId: alice,
        permission: "ViewOnly",
      });

      const result = await changePermission({
        circleId,
        actorId: owner,
        memberId: alice,
        permission: "Exchange",
      });

      expect(result.isOk).toBe(true);
      const circle = await circles.findById(circleId);
      expect(
        circle?.members.find((m) => m.memberId === alice)?.permission,
      ).toBe("Exchange");
    });

    it("rejects a no-op permission change", async () => {
      const circleId = await openCircle();
      await addMember({
        circleId,
        actorId: owner,
        memberId: alice,
        permission: "ViewOnly",
      });

      const result = await changePermission({
        circleId,
        actorId: owner,
        memberId: alice,
        permission: "ViewOnly",
      });

      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("DuplicatePermission");
    });

    it("returns CircleNotFound for an unknown circle", async () => {
      const result = await changePermission({
        circleId: missingCircle,
        actorId: owner,
        memberId: alice,
        permission: "Admin",
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CircleNotFound");
    });
  });

  describe("makeShareCopyToCircle", () => {
    it("shares a copy by an admin and publishes CopySharedToCircle", async () => {
      const circleId = await openCircle();
      events.published.length = 0;

      const result = await shareCopy({ circleId, actorId: owner, copyId });

      expect(result.isOk).toBe(true);
      expect(events.names()).toEqual(["CopySharedToCircle"]);
    });

    it("rejects a non-admin actor", async () => {
      const circleId = await openCircle();
      await addMember({
        circleId,
        actorId: owner,
        memberId: alice,
        permission: "Exchange",
      });
      events.published.length = 0;

      const result = await shareCopy({ circleId, actorId: alice, copyId });

      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("NotCircleAdmin");
      expect(events.published).toHaveLength(0);
    });

    it("returns CircleNotFound for an unknown circle", async () => {
      const result = await shareCopy({
        circleId: missingCircle,
        actorId: owner,
        copyId,
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CircleNotFound");
    });
  });

  describe("listForMember", () => {
    it("returns every circle a member belongs to (the VisibilityPolicy wiring seam)", async () => {
      const first = await openCircle();
      const second = await openCircle();
      await addMember({
        circleId: first,
        actorId: owner,
        memberId: alice,
        permission: "ViewOnly",
      });

      const ownerCircles = await circles.listForMember(owner);
      const aliceCircles = await circles.listForMember(alice);

      expect(ownerCircles.map((c) => c.id).sort()).toEqual(
        [first, second].sort(),
      );
      expect(aliceCircles.map((c) => c.id)).toEqual([first]);
    });
  });
});

src/social/application/use-cases/request.source:
import { beforeEach, describe, expect, it, vi } from "vitest";
import { toMemberId } from "../../../shared-kernel";
import { Follow, FollowRequest } from "../../domain";
import {
  FixedClock,
  InMemoryFollowRepository,
  InMemoryFollowRequestRepository,
  RecordingEventPublisher,
  SequentialFollowIdGenerator,
  SequentialFollowRequestIdGenerator,
} from "../testing";
import { COOLDOWN_MS, makeRequestFollow } from "./request-follow";

const alice = toMemberId("alice");
const bob = toMemberId("bob");
const NOW = new Date("2026-07-11T10:00:00Z");

describe("makeRequestFollow", () => {
  let requests: InMemoryFollowRequestRepository;
  let follows: InMemoryFollowRepository;
  let events: RecordingEventPublisher;
  let requestIds: SequentialFollowRequestIdGenerator;
  let request: ReturnType<typeof makeRequestFollow>;

  // NOTE: requestIds is created once in beforeEach and reused across build() calls, not
  // recreated here. Re-creating it per build() would reset the id counter to 1 every time a
  // test advances the clock, making a genuinely "fresh" request collide with the id of the
  // stale one it replaced — a false pass/fail independent of the use case under test.
  const build = (now: Date) => {
    request = makeRequestFollow({
      requests,
      follows,
      requestIds,
      events,
      clock: new FixedClock(now),
    });
  };

  beforeEach(() => {
    requests = new InMemoryFollowRequestRepository();
    follows = new InMemoryFollowRepository();
    events = new RecordingEventPublisher();
    requestIds = new SequentialFollowRequestIdGenerator();
    build(NOW);
  });

  it("creates a pending request and publishes FollowRequested", async () => {
    const result = await request({ requesterId: alice, targetId: bob });
    expect(result.isOk).toBe(true);
    expect(requests.size()).toBe(1);
    expect(events.names()).toEqual(["FollowRequested"]);
  });

  it("is idempotent while a request is pending: returns the same id, no new row/event", async () => {
    const first = await request({ requesterId: alice, targetId: bob });
    const second = await request({ requesterId: alice, targetId: bob });
    expect(second.isOk).toBe(true);
    if (first.isOk && second.isOk) expect(second.value).toBe(first.value);
    expect(requests.size()).toBe(1);
    expect(events.names()).toEqual(["FollowRequested"]); // only the first
  });

  it("rejects when the requester already follows the target", async () => {
    const edge = Follow.establish({
      id: new SequentialFollowIdGenerator().next(),
      followerId: alice,
      followeeId: bob,
      now: NOW,
    });
    if (!edge.isOk) throw new Error("setup");
    await follows.save(edge.value);

    const result = await request({ requesterId: alice, targetId: bob });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("AlreadyFollowing");
  });

  it("silently no-ops during the decline cooldown (indistinguishable from pending)", async () => {
    const first = await request({ requesterId: alice, targetId: bob });
    if (!first.isOk) throw new Error("setup");
    const row = await requests.findByPair(alice, bob);
    if (!row) throw new Error("setup");
    row.decline(NOW);
    await requests.save(row);

    // A non-cancelled cooldown request must be a PURE read: the row is left exactly as-is, so
    // the use case must not re-save it (only the cancelled-row reopen path saves).
    const saveSpy = vi.spyOn(requests, "save");
    build(new Date(NOW.getTime() + COOLDOWN_MS - 1000)); // still inside cooldown
    const again = await request({ requesterId: alice, targetId: bob });
    expect(again.isOk).toBe(true);
    if (again.isOk) expect(again.value).toBe(first.value);
    expect(requests.size()).toBe(1); // no new row
    expect(saveSpy).not.toHaveBeenCalled();
  });

  it("re-request inside the cooldown after a cancel resumes the mask: same id, no new row, cancelledAt cleared, no event", async () => {
    const first = await request({ requesterId: alice, targetId: bob });
    if (!first.isOk) throw new Error("setup");
    const row = await requests.findByPair(alice, bob);
    if (!row) throw new Error("setup");
    row.decline(NOW);
    if (row.markCancelledWhileDeclined(NOW).isErr) throw new Error("setup");
    await requests.save(row);
    events.published.length = 0; // only assert on events the re-request itself publishes

    build(new Date(NOW.getTime() + COOLDOWN_MS - 1000)); // still inside cooldown
    const again = await request({ requesterId: alice, targetId: bob });
    expect(again.isOk).toBe(true);
    if (again.isOk) expect(again.value).toBe(first.value); // same id, silent
    expect(requests.size()).toBe(1); // no new row
    const reopened = await requests.findByPair(alice, bob);
    expect(reopened?.toState().cancelledAt).toBeUndefined(); // mask resumed
    expect(events.names()).toEqual([]); // silent: no event
  });

  it("re-request after the cooldown expires on a cancelled decline creates a fresh request", async () => {
    const first = await request({ requesterId: alice, targetId: bob });
    if (!first.isOk) throw new Error("setup");
    const row = await requests.findByPair(alice, bob);
    if (!row) throw new Error("setup");
    row.decline(NOW);
    if (row.markCancelledWhileDeclined(NOW).isErr) throw new Error("setup");
    await requests.save(row);
    events.published.length = 0;

    build(new Date(NOW.getTime() + COOLDOWN_MS + 1000)); // past cooldown
    const again = await request({ requesterId: alice, targetId: bob });
    expect(again.isOk).toBe(true);
    if (again.isOk) expect(again.value).not.toBe(first.value); // fresh id
    expect(requests.size()).toBe(1); // stale cancelled row replaced
    const fresh = await requests.findByPair(alice, bob);
    expect(fresh?.status).toBe("pending");
    expect(fresh?.toState().cancelledAt).toBeUndefined();
    expect(events.names()).toEqual(["FollowRequested"]);
  });

  it("re-opens with a fresh request after the cooldown has passed", async () => {
    const first = await request({ requesterId: alice, targetId: bob });
    if (!first.isOk) throw new Error("setup");
    const row = await requests.findByPair(alice, bob);
    if (!row) throw new Error("setup");
    row.decline(NOW);
    await requests.save(row);

    build(new Date(NOW.getTime() + COOLDOWN_MS + 1000)); // past cooldown
    const again = await request({ requesterId: alice, targetId: bob });
    expect(again.isOk).toBe(true);
    if (again.isOk) expect(again.value).not.toBe(first.value);
    expect(requests.size()).toBe(1); // stale row replaced
    const fresh = await requests.findByPair(alice, bob);
    expect(fresh?.status).toBe("pending");
  });

  it("re-opens exactly at the cooldown boundary (not swallowed): boundary is < COOLDOWN_MS, not <=", async () => {
    const first = await request({ requesterId: alice, targetId: bob });
    if (!first.isOk) throw new Error("setup");
    const row = await requests.findByPair(alice, bob);
    if (!row) throw new Error("setup");
    row.decline(NOW);
    await requests.save(row);

    build(new Date(NOW.getTime() + COOLDOWN_MS)); // exactly at the boundary
    const again = await request({ requesterId: alice, targetId: bob });
    expect(again.isOk).toBe(true);
    if (again.isOk) expect(again.value).not.toBe(first.value);
    const fresh = await requests.findByPair(alice, bob);
    expect(fresh?.status).toBe("pending");
  });

  it("replaces a stale approved row immediately (cooldown applies only to declines)", async () => {
    // An approved request whose Follow edge was later removed by an unfollow: the follows
    // repo is EMPTY (otherwise the already-following rejection fires first), only the stale
    // approved row remains. Seeded directly so the event recorder stays clean.
    const seeded = FollowRequest.request({
      id: requestIds.next(),
      requesterId: alice,
      targetId: bob,
      now: NOW,
    });
    if (seeded.isErr) throw new Error("setup");
    if (seeded.value.approve(NOW).isErr) throw new Error("setup");
    await requests.save(seeded.value);

    build(new Date(NOW.getTime() + 1000)); // well within COOLDOWN_MS
    const again = await request({ requesterId: alice, targetId: bob });
    expect(again.isOk).toBe(true);
    if (again.isOk) expect(again.value).not.toBe(seeded.value.id);
    expect(requests.size()).toBe(1); // old approved row gone, fresh row in its place
    const fresh = await requests.findByPair(alice, bob);
    expect(fresh?.status).toBe("pending");
    expect(events.names()).toEqual(["FollowRequested"]);
  });

  it("pins the cooldown constant at exactly 7 days", () => {
    // Literal on the expected side so an arithmetic mutant in the formula cannot survive.
    expect(COOLDOWN_MS).toBe(604_800_000);
  });

  it("rejects a self-request", async () => {
    const result = await request({ requesterId: alice, targetId: alice });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("SelfFollow");
  });
});

