import { beforeEach, describe, expect, it, vi } from "vitest";
import { toPuzzleDefinitionId, toSubmitterId } from "../../../shared-kernel";

import {
  FixedClock,
  InMemoryPuzzleDefinitionRepository,
  RecordingEventPublisher,
  SequentialIdGenerator,
} from "../testing";
import { makeApprovePuzzleDefinition } from "./approve-puzzle-definition";
import { makeDisablePuzzleDefinition } from "./disable-puzzle-definition";
import { makeReenablePuzzleDefinition } from "./reenable-puzzle-definition";
import { makeRejectPuzzleDefinition } from "./reject-puzzle-definition";
import { makeSubmitPuzzleDefinition } from "./submit-puzzle-definition";
import { makeUpdatePuzzleDefinition } from "./update-puzzle-definition";

const submitter = toSubmitterId("alice");
const NOW = new Date("2026-06-08T10:00:00Z");

describe("Catalog PuzzleDefinition use cases", () => {
  let repo: InMemoryPuzzleDefinitionRepository;
  let events: RecordingEventPublisher;
  let deps: {
    definitions: InMemoryPuzzleDefinitionRepository;
    ids: SequentialIdGenerator;
    events: RecordingEventPublisher;
    clock: FixedClock;
  };

  beforeEach(() => {
    repo = new InMemoryPuzzleDefinitionRepository();
    events = new RecordingEventPublisher();
    deps = {
      definitions: repo,
      ids: new SequentialIdGenerator(),
      events,
      clock: new FixedClock(NOW),
    };
  });

  const submitOk = async (barcodes?: { ean?: string; upc?: string }) => {
    const submit = makeSubmitPuzzleDefinition(deps);
    const r = await submit({
      title: "Starry Night",
      pieceCount: 1000,
      submittedBy: submitter,
      barcodes,
    });
    if (!r.isOk) throw new Error(`submit failed: ${r.error.code}`);
    return r.value;
  };

  it("submits a definition, saving state and publishing PuzzleDefinitionSubmitted", async () => {
    const id = await submitOk();
    expect(repo.size()).toBe(1);
    expect(events.names()).toEqual(["PuzzleDefinitionSubmitted"]);
    expect(id).toBe(toPuzzleDefinitionId("pd-1"));
  });

  it("leaves a normal submission pending (no autoApprove)", async () => {
    const id = await submitOk();
    const stored = await repo.findById(id);
    expect(stored?.status).toBe("pending");
  });

  it("auto-approves the submission when autoApprove is set, saving it approved and emitting both events", async () => {
    const submit = makeSubmitPuzzleDefinition(deps);
    const r = await submit({
      title: "Starry Night",
      pieceCount: 1000,
      submittedBy: submitter,
      autoApprove: true,
    });
    if (!r.isOk) throw new Error(`submit failed: ${r.error.code}`);
    const stored = await repo.findById(r.value);
    expect(stored?.status).toBe("approved");
    expect(events.names()).toEqual([
      "PuzzleDefinitionSubmitted",
      "PuzzleDefinitionApproved",
    ]);
  });

  it("rejects a duplicate barcode via the repository (DuplicateBarcode)", async () => {
    await submitOk({ ean: "4006381333931" });
    const submit = makeSubmitPuzzleDefinition(deps);

    const second = await submit({
      title: "Another",
      pieceCount: 500,
      submittedBy: submitter,
      barcodes: { ean: "4006381333931" },
    });
    expect(second.isErr).toBe(true);
    if (second.isErr) expect(second.error.code).toBe("DuplicateBarcode");
    expect(repo.size()).toBe(1); // no second definition written
  });

  // Only PRESENT barcodes are checked for uniqueness: absent (undefined) identifiers are
  // filtered out of the candidate list, so the repository is queried solely with the EAN —
  // never with `undefined` (kills the dropped `.filter`).
  it("queries uniqueness only for the supplied barcodes, never for absent ones", async () => {
    const lookup = vi.spyOn(repo, "findByBarcode");
    const submit = makeSubmitPuzzleDefinition(deps);
    const r = await submit({
      title: "Filtered",
      pieceCount: 1000,
      submittedBy: submitter,
      barcodes: { ean: "4006381333931" }, // upc / modelNumber absent
    });
    expect(r.isOk).toBe(true);
    expect(lookup).toHaveBeenCalledTimes(1);
    expect(lookup).toHaveBeenCalledWith("4006381333931");
  });

  it("checks every distinct supplied barcode for a duplicate (UPC clash too)", async () => {
    await submitOk({ ean: "4006381333931" });
    const submit = makeSubmitPuzzleDefinition(deps);
    // Reuse the same EAN under a different title: the EAN candidate must trigger the clash.
    const dup = await submit({
      title: "UPC clash",
      pieceCount: 500,
      submittedBy: submitter,
      barcodes: { upc: "036000291452", ean: "4006381333931" },
    });
    expect(dup.isErr).toBe(true);
    if (dup.isErr) expect(dup.error.code).toBe("DuplicateBarcode");
  });

  it("delegates barcode-format validation to the aggregate", async () => {
    const submit = makeSubmitPuzzleDefinition(deps);
    const r = await submit({
      title: "Bad",
      pieceCount: 100,
      submittedBy: submitter,
      barcodes: { ean: "nope" },
    });
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("InvalidBarcode");
    expect(events.published).toHaveLength(0);
  });

  it("approves a stored definition and publishes PuzzleDefinitionApproved", async () => {
    const id = await submitOk();
    events.published.length = 0;
    const approve = makeApprovePuzzleDefinition(deps);
    const r = await approve({ puzzleDefinitionId: id });
    expect(r.isOk).toBe(true);
    expect(events.names()).toEqual(["PuzzleDefinitionApproved"]);
  });

  it("rejects approval of an unknown definition (PuzzleDefinitionNotFound)", async () => {
    const approve = makeApprovePuzzleDefinition(deps);
    const r = await approve({
      puzzleDefinitionId: toPuzzleDefinitionId("missing"),
    });
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("PuzzleDefinitionNotFound");
  });

  it("surfaces the aggregate's illegal-transition on re-approval", async () => {
    const id = await submitOk();
    const approve = makeApprovePuzzleDefinition(deps);
    await approve({ puzzleDefinitionId: id });
    const again = await approve({ puzzleDefinitionId: id });
    expect(again.isErr).toBe(true);
    if (again.isErr) expect(again.error.code).toBe("IllegalApprovalTransition");
  });

  it("disables a stored approved definition and publishes PuzzleDefinitionDisabled", async () => {
    const id = await submitOk();
    const approve = makeApprovePuzzleDefinition(deps);
    await approve({ puzzleDefinitionId: id });
    events.published.length = 0;

    const disable = makeDisablePuzzleDefinition(deps);
    const r = await disable({ puzzleDefinitionId: id });
    expect(r.isOk).toBe(true);
    expect(events.names()).toEqual(["PuzzleDefinitionDisabled"]);
    const stored = await repo.findById(id);
    expect(stored?.status).toBe("disabled");
  });

  it("re-enables a disabled definition and publishes PuzzleDefinitionReenabled", async () => {
    const id = await submitOk();
    await makeApprovePuzzleDefinition(deps)({ puzzleDefinitionId: id });
    await makeDisablePuzzleDefinition(deps)({ puzzleDefinitionId: id });
    events.published.length = 0;

    const reenable = makeReenablePuzzleDefinition(deps);
    const r = await reenable({ puzzleDefinitionId: id });
    expect(r.isOk).toBe(true);
    expect(events.names()).toEqual(["PuzzleDefinitionReenabled"]);
    const stored = await repo.findById(id);
    expect(stored?.status).toBe("approved");
  });

  it("surfaces the aggregate's illegal-transition when disabling a pending definition", async () => {
    const id = await submitOk();
    const disable = makeDisablePuzzleDefinition(deps);
    const r = await disable({ puzzleDefinitionId: id });
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("IllegalApprovalTransition");
  });

  it("rejects disabling an unknown definition (PuzzleDefinitionNotFound)", async () => {
    const disable = makeDisablePuzzleDefinition(deps);
    const r = await disable({
      puzzleDefinitionId: toPuzzleDefinitionId("missing"),
    });
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("PuzzleDefinitionNotFound");
  });

  it("rejects a definition and publishes PuzzleDefinitionRejected", async () => {
    const id = await submitOk();
    events.published.length = 0;
    const reject = makeRejectPuzzleDefinition(deps);
    const r = await reject({ puzzleDefinitionId: id });
    expect(r.isOk).toBe(true);
    expect(events.names()).toEqual(["PuzzleDefinitionRejected"]);
  });

  it("updates a definition and publishes PuzzleDefinitionUpdated", async () => {
    const id = await submitOk();
    events.published.length = 0;
    const update = makeUpdatePuzzleDefinition(deps);
    const r = await update({
      puzzleDefinitionId: id,
      changes: { brand: "Ravensburger" },
    });
    expect(r.isOk).toBe(true);
    expect(events.names()).toEqual(["PuzzleDefinitionUpdated"]);
    const stored = await repo.findById(id);
    expect(stored?.toState().brand).toBe("Ravensburger");
  });
});

src/social/application/use-cases/resolve.source:
import { beforeEach, describe, expect, it } from "vitest";
import { toMemberId } from "../../../shared-kernel";
import { Follow, FollowRequest, FollowRequestId } from "../../domain";
import {
  FixedClock,
  InMemoryFollowRepository,
  InMemoryFollowRequestRepository,
  RecordingEventPublisher,
  SequentialFollowIdGenerator,
  SequentialFollowRequestIdGenerator,
} from "../testing";
import { makeApproveFollowRequest } from "./approve-follow-request";
import { makeCancelFollowRequest } from "./cancel-follow-request";
import { makeDeclineFollowRequest } from "./decline-follow-request";
import { makeRequestFollow } from "./request-follow";

const alice = toMemberId("alice"); // requester
const bob = toMemberId("bob"); // target
const carol = toMemberId("carol"); // bystander
const NOW = new Date("2026-07-11T10:00:00Z");

describe("resolving follow requests", () => {
  let requests: InMemoryFollowRequestRepository;
  let follows: InMemoryFollowRepository;
  let events: RecordingEventPublisher;
  let requestId: FollowRequestId;
  let followIds: SequentialFollowIdGenerator;
  let approve: ReturnType<typeof makeApproveFollowRequest>;
  let decline: ReturnType<typeof makeDeclineFollowRequest>;
  let cancel: ReturnType<typeof makeCancelFollowRequest>;

  beforeEach(async () => {
    requests = new InMemoryFollowRequestRepository();
    follows = new InMemoryFollowRepository();
    events = new RecordingEventPublisher();
    const clock = new FixedClock(NOW);
    const request = makeRequestFollow({
      requests,
      follows,
      requestIds: new SequentialFollowRequestIdGenerator(),
      events,
      clock,
    });
    const created = await request({ requesterId: alice, targetId: bob });
    if (!created.isOk) throw new Error("setup");
    requestId = created.value;
    events.published.length = 0; // discard the FollowRequested from setup

    // Shared across the whole test (not recreated per `it`) so a test that seeds an extra Follow
    // edge before calling approve() draws from the same counter as approve's own id generator —
    // otherwise two independently-fresh generators both mint "follow-1" and the second save()
    // silently clobbers the first in the in-memory store (keyed by FollowId).
    followIds = new SequentialFollowIdGenerator();
    const deps = {
      requests,
      follows,
      followIds,
      events,
      clock,
    };
    approve = makeApproveFollowRequest(deps);
    decline = makeDeclineFollowRequest({ requests, events, clock });
    cancel = makeCancelFollowRequest({ requests, clock });
  });

  it("approve: creates the requester→target edge and publishes both events", async () => {
    const result = await approve({ requestId, actorId: bob });
    expect(result.isOk).toBe(true);
    if (!result.isOk) return;

    expect(result.value.requesterId).toBe(alice);
    expect(result.value.alreadyFollowsBack).toBe(false);
    expect(await follows.find(alice, bob)).not.toBeNull();
    expect(events.names().sort()).toEqual([
      "FollowRequestApproved",
      "MemberFollowed",
    ]);
  });

  it("approve: reports alreadyFollowsBack when the target already follows the requester", async () => {
    const back = Follow.establish({
      id: followIds.next(),
      followerId: bob,
      followeeId: alice,
      now: NOW,
    });
    if (!back.isOk) throw new Error("setup");
    await follows.save(back.value);

    const result = await approve({ requestId, actorId: bob });
    expect(result.isOk).toBe(true);
    if (result.isOk) expect(result.value.alreadyFollowsBack).toBe(true);
    // The requester→target edge is genuinely new here (only the reverse edge pre-existed), so
    // both events fire, same as the plain approve case.
    expect(events.names().sort()).toEqual([
      "FollowRequestApproved",
      "MemberFollowed",
    ]);
  });

  it("approve: tolerates an already-existing requester→target edge (no duplicate edge, no extra MemberFollowed)", async () => {
    const stray = Follow.establish({
      id: followIds.next(),
      followerId: alice,
      followeeId: bob,
      now: NOW,
    });
    if (!stray.isOk) throw new Error("setup");
    await follows.save(stray.value);

    const result = await approve({ requestId, actorId: bob });
    expect(result.isOk).toBe(true);
    expect(follows.size()).toBe(1); // no second edge created
    expect(events.names()).toEqual(["FollowRequestApproved"]); // no MemberFollowed
  });

  it("approve: surfaces a SelfFollow error if the loaded request is (invalidly) self-targeted", async () => {
    // Contrives a state FollowRequest.request() itself would reject, to exercise the
    // duplicate-tolerant edge-creation's own error path (Follow.establish rejecting a
    // self-follow), which is otherwise unreachable through the public API.
    const corrupt = FollowRequest.rehydrate({
      id: requestId,
      requesterId: alice,
      targetId: alice,
      status: "pending",
      createdAt: NOW,
    });
    await requests.save(corrupt);

    const result = await approve({ requestId, actorId: alice });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("SelfFollow");
  });

  it("approve: only the target may approve", async () => {
    const result = await approve({ requestId, actorId: carol });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("NotRequestTarget");
    expect(await follows.find(alice, bob)).toBeNull();
  });

  it("approve: unknown request id", async () => {
    const result = await approve({
      requestId: "nope" as FollowRequestId,
      actorId: bob,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("RequestNotFound");
  });

  it("decline: marks declined, publishes FollowRequestDeclined, creates no edge", async () => {
    const result = await decline({ requestId, actorId: bob });
    expect(result.isOk).toBe(true);
    expect(events.names()).toEqual(["FollowRequestDeclined"]);
    expect(await follows.find(alice, bob)).toBeNull();
    const row = await requests.findById(requestId);
    expect(row?.status).toBe("declined");
  });

  it("decline: only the target may decline", async () => {
    const result = await decline({ requestId, actorId: alice });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("NotRequestTarget");
  });

  it("decline: unknown request id", async () => {
    const result = await decline({
      requestId: "nope" as FollowRequestId,
      actorId: bob,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("RequestNotFound");
  });

  it("decline: declining an already-resolved request fails (RequestNotPending)", async () => {
    const first = await decline({ requestId, actorId: bob });
    expect(first.isOk).toBe(true);

    const second = await decline({ requestId, actorId: bob });
    expect(second.isErr).toBe(true);
    if (second.isErr) expect(second.error.code).toBe("RequestNotPending");
  });

  it("cancel: the requester withdraws their pending request (row removed, no events)", async () => {
    const result = await cancel({ requestId, actorId: alice });
    expect(result.isOk).toBe(true);
    expect(await requests.findById(requestId)).toBeNull();
    expect(events.published).toHaveLength(0);
  });

  it("cancel: a declined-in-cooldown request is retained with cancelledAt set (row kept, no events)", async () => {
    const declineResult = await decline({ requestId, actorId: bob });
    expect(declineResult.isOk).toBe(true);
    events.published.length = 0; // discard the FollowRequestDeclined from the decline

    const result = await cancel({ requestId, actorId: alice });
    expect(result.isOk).toBe(true);
    // The decline record must survive a cancel, so the row is kept (not removed) and carries
    // the cancelled mark that stops the read side masking it as pending.
    const row = await requests.findById(requestId);
    expect(row).not.toBeNull();
    expect(row?.status).toBe("declined");
    expect(row?.toState().cancelledAt).toEqual(NOW);
    expect(events.published).toHaveLength(0);
  });

  it("cancel: only the requester may cancel", async () => {
    const result = await cancel({ requestId, actorId: bob });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("NotRequestOwner");
  });

  it("cancel: unknown request id", async () => {
    const result = await cancel({
      requestId: "nope" as FollowRequestId,
      actorId: alice,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("RequestNotFound");
  });

  it("approve after decline fails (RequestNotPending)", async () => {
    await decline({ requestId, actorId: bob });
    const result = await approve({ requestId, actorId: bob });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("RequestNotPending");
  });
});

src/sharing/domain/circle.spec.ts.source:
import { describe, expect, it } from "vitest";
import {
  toCircleId,
  toCopyId,
  toMemberId,
  toMembershipId,
} from "../../shared-kernel";
import { Circle } from "./circle";
import { MembershipId } from "./ids";

const owner = toMemberId("owner");
const alice = toMemberId("alice");
const bob = toMemberId("bob");
const stranger = toMemberId("stranger");
const circleId = toCircleId("circle-1");
const NOW = new Date("2026-06-08T10:00:00Z");

let seq = 0;
const membershipId = (): MembershipId => {
  seq += 1;
  return toMembershipId(`membership-${seq}`);
};

const newCircle = (): Circle =>
  Circle.create({
    id: circleId,
    ownerId: owner,
    ownerMembershipId: membershipId(),
    name: "Family",
    now: NOW,
  });

describe("Circle", () => {
  it("opens with the owner as its only member, implicitly Admin", () => {
    const ownerMembershipId = membershipId();
    const circle = Circle.create({
      id: circleId,
      ownerId: owner,
      ownerMembershipId,
      name: "Family",
      now: NOW,
    });
    expect(circle.name).toBe("Family");
    expect(circle.ownerId).toBe(owner);
    expect(circle.isMember(owner)).toBe(true);
    expect(circle.members).toHaveLength(1);
    expect(circle.members[0].permission).toBe("Admin");
    expect(circle.members[0].id).toBe(ownerMembershipId);
    expect(circle.members[0].joinedAt).toBe(NOW);
  });

  it("records CircleCreated on open", () => {
    const events = newCircle().pullEvents();
    expect(events.map((e) => e.name)).toEqual(["CircleCreated"]);
  });

  describe("addMember", () => {
    it("lets an admin add a member and records MemberJoinedCircle", () => {
      const circle = newCircle();
      circle.pullEvents();

      const result = circle.addMember(
        owner,
        membershipId(),
        alice,
        "ViewOnly",
        NOW,
      );

      expect(result.isOk).toBe(true);
      expect(circle.isMember(alice)).toBe(true);
      expect(circle.pullEvents().map((e) => e.name)).toEqual([
        "MemberJoinedCircle",
      ]);
    });

    it("rejects a non-admin actor", () => {
      const circle = newCircle();
      circle.addMember(owner, membershipId(), alice, "ViewOnly", NOW); // alice is ViewOnly
      circle.pullEvents();

      const result = circle.addMember(
        alice,
        membershipId(),
        bob,
        "ViewOnly",
        NOW,
      );

      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("NotCircleAdmin");
      expect(circle.isMember(bob)).toBe(false);
      expect(circle.pullEvents()).toHaveLength(0);
    });

    it("rejects an actor who is not a member at all", () => {
      const circle = newCircle();
      const result = circle.addMember(
        stranger,
        membershipId(),
        alice,
        "Admin",
        NOW,
      );
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("NotCircleAdmin");
    });

    it("rejects a duplicate member", () => {
      const circle = newCircle();
      circle.addMember(owner, membershipId(), alice, "ViewOnly", NOW);
      circle.pullEvents();

      const result = circle.addMember(
        owner,
        membershipId(),
        alice,
        "Admin",
        NOW,
      );

      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("AlreadyMember");
      expect(circle.members).toHaveLength(2);
    });

    it("lets a promoted admin add further members", () => {
      const circle = newCircle();
      circle.addMember(owner, membershipId(), alice, "Admin", NOW);

      const result = circle.addMember(
        alice,
        membershipId(),
        bob,
        "ViewOnly",
        NOW,
      );
      expect(result.isOk).toBe(true);
      expect(circle.isMember(bob)).toBe(true);
    });
  });

  describe("removeMember", () => {
    it("lets an admin remove a member", () => {
      const circle = newCircle();
      circle.addMember(owner, membershipId(), alice, "ViewOnly", NOW);

      const result = circle.removeMember(owner, alice);
      expect(result.isOk).toBe(true);
      expect(circle.isMember(alice)).toBe(false);
      expect(circle.isMember(owner)).toBe(true); // only the target is dropped
    });

    it("rejects a non-admin actor", () => {
      const circle = newCircle();
      circle.addMember(owner, membershipId(), alice, "ViewOnly", NOW);
      circle.addMember(owner, membershipId(), bob, "ViewOnly", NOW);

      const result = circle.removeMember(alice, bob);
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("NotCircleAdmin");
      expect(circle.isMember(bob)).toBe(true);
    });

    it("refuses to remove the owner", () => {
      const circle = newCircle();
      const result = circle.removeMember(owner, owner);
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CannotRemoveOwner");
      expect(circle.isMember(owner)).toBe(true);
    });

    it("rejects removing a non-member", () => {
      const circle = newCircle();
      const result = circle.removeMember(owner, alice);
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("NotAMember");
    });
  });

  describe("changePermission", () => {
    it("lets an admin change a member's permission", () => {
      const circle = newCircle();
      circle.addMember(owner, membershipId(), alice, "ViewOnly", NOW);

      const result = circle.changePermission(owner, alice, "Exchange");
      expect(result.isOk).toBe(true);
      expect(circle.members.find((m) => m.memberId === alice)?.permission).toBe(
        "Exchange",
      );
      // Only the named member changes; the owner's seat is untouched.
      expect(circle.members.find((m) => m.memberId === owner)?.permission).toBe(
        "Admin",
      );
    });

    it("rejects a non-admin actor", () => {
      const circle = newCircle();
      circle.addMember(owner, membershipId(), alice, "ViewOnly", NOW);
      circle.addMember(owner, membershipId(), bob, "ViewOnly", NOW);

      const result = circle.changePermission(alice, bob, "Admin");
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("NotCircleAdmin");
    });

    it("refuses to change the owner's permission", () => {
      const circle = newCircle();
      const result = circle.changePermission(owner, owner, "ViewOnly");
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CannotRemoveOwner");
      expect(circle.members[0].permission).toBe("Admin");
    });

    it("rejects changing a non-member", () => {
      const circle = newCircle();
      const result = circle.changePermission(owner, alice, "Admin");
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("NotAMember");
    });

    it("rejects a no-op change to the same permission", () => {
      const circle = newCircle();
      circle.addMember(owner, membershipId(), alice, "ViewOnly", NOW);

      const result = circle.changePermission(owner, alice, "ViewOnly");
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("DuplicatePermission");
    });
  });

  describe("shareCopy", () => {
    const copyId = toCopyId("copy-1");

    it("lets an admin share a copy and records CopySharedToCircle", () => {
      const circle = newCircle();
      circle.pullEvents();

      const result = circle.shareCopy(owner, copyId, NOW);
      expect(result.isOk).toBe(true);
      const events = circle.pullEvents();
      expect(events.map((e) => e.name)).toEqual(["CopySharedToCircle"]);
    });

    it("rejects a non-admin actor", () => {
      const circle = newCircle();
      circle.addMember(owner, membershipId(), alice, "Exchange", NOW);
      circle.pullEvents();

      const result = circle.shareCopy(alice, copyId, NOW);
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("NotCircleAdmin");
      expect(circle.pullEvents()).toHaveLength(0);
    });
  });

  it("round-trips through toState/rehydrate preserving memberships", () => {
    const circle = newCircle();
    circle.addMember(owner, membershipId(), alice, "Exchange", NOW);

    const rehydrated = Circle.rehydrate(circle.toState());
    expect(rehydrated.members).toHaveLength(2);
    expect(rehydrated.isMember(alice)).toBe(true);
    expect(
      rehydrated.members.find((m) => m.memberId === alice)?.permission,
    ).toBe("Exchange");
  });
});

src/exchange/application/use-cases/propo.source:
import { beforeEach, describe, expect, it } from "vitest";
import { toCopyId, toMemberId } from "../../../shared-kernel";
import { ExchangeTermsInput, Money } from "../../domain";
import { CopyView } from "../ports/out/copy.port";
import {
  FakeCopyPort,
  FixedClock,
  InMemoryExchangeRepository,
  RecordingEventPublisher,
  SequentialIdGenerator,
} from "../testing";
import { makeProposeExchange } from "./propose-exchange";

const alice = toMemberId("alice"); // initiator
const bob = toMemberId("bob"); // recipient
const requestedId = toCopyId("requested");
const offeredId = toCopyId("offered");
const NOW = new Date("2026-06-08T10:00:00Z");

const price = (): Money => {
  const m = Money.create(2500, "EUR");
  if (!m.isOk) throw new Error("setup");
  return m.value;
};

// A copy with all availability flags off; tests turn on exactly what they need.
const copy = (
  over: Partial<CopyView> & Pick<CopyView, "id" | "ownerId">,
): CopyView => ({
  availability: { forTrade: false, forSale: false, forLend: false },
  ...over,
});

describe("makeProposeExchange", () => {
  let repo: InMemoryExchangeRepository;
  let copies: FakeCopyPort;
  let events: RecordingEventPublisher;
  let propose: ReturnType<typeof makeProposeExchange>;

  beforeEach(() => {
    repo = new InMemoryExchangeRepository();
    copies = new FakeCopyPort();
    events = new RecordingEventPublisher();
    propose = makeProposeExchange({
      exchanges: repo,
      copies,
      ids: new SequentialIdGenerator(),
      events,
      clock: new FixedClock(NOW),
    });
  });

  const swapTerms: ExchangeTermsInput = {
    kind: "swap",
    offeredCopyId: offeredId,
  };
  const saleTerms = (): ExchangeTermsInput => ({
    kind: "sale",
    price: price(),
  });
  const lendTerms: ExchangeTermsInput = {
    kind: "lend",
    returnDate: new Date("2026-06-20T10:00:00Z"),
  };

  it("proposes a swap, saving state and publishing ExchangeProposed", async () => {
    copies
      .seed(
        copy({
          id: requestedId,
          ownerId: bob,
          availability: { forTrade: true, forSale: false, forLend: false },
        }),
      )
      .seed(copy({ id: offeredId, ownerId: alice }));

    const result = await propose({
      initiatorId: alice,
      recipientId: bob,
      kind: "swap",
      requestedCopyId: requestedId,
      terms: swapTerms,
    });

    expect(result.isOk).toBe(true);
    expect(repo.size()).toBe(1);
    expect(events.names()).toEqual(["ExchangeProposed"]);
  });

  it("rejects a duplicate active proposal for the same requested copy", async () => {
    copies
      .seed(
        copy({
          id: requestedId,
          ownerId: bob,
          availability: { forTrade: true, forSale: false, forLend: false },
        }),
      )
      .seed(copy({ id: offeredId, ownerId: alice }));
    const cmd = {
      initiatorId: alice,
      recipientId: bob,
      kind: "swap" as const,
      requestedCopyId: requestedId,
      terms: swapTerms,
    };
    expect((await propose(cmd)).isOk).toBe(true);

    const second = await propose(cmd);
    expect(second.isErr).toBe(true);
    if (second.isErr) expect(second.error.code).toBe("DuplicateProposal");
    expect(repo.size()).toBe(1); // no second exchange written
  });

  it("rejects when the requested copy does not exist", async () => {
    const result = await propose({
      initiatorId: alice,
      recipientId: bob,
      kind: "sale",
      requestedCopyId: requestedId,
      terms: saleTerms(),
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("CopyNotFound");
    expect(events.published).toHaveLength(0);
  });

  // The CORRECTED availability direction: available ⇒ ok, unavailable ⇒ reject.
  describe("availability is checked per kind (corrected direction)", () => {
    it.each<["swap" | "sale" | "lend", keyof CopyView["availability"]]>([
      ["swap", "forTrade"],
      ["sale", "forSale"],
      ["lend", "forLend"],
    ])("%s proceeds only when %s is true", async (kind, flag) => {
      const terms: ExchangeTermsInput =
        kind === "swap" ? swapTerms : kind === "sale" ? saleTerms() : lendTerms;

      // available ⇒ ok
      const available = new FakeCopyPort()
        .seed(
          copy({
            id: requestedId,
            ownerId: bob,
            availability: {
              forTrade: false,
              forSale: false,
              forLend: false,
              [flag]: true,
            },
          }),
        )
        .seed(copy({ id: offeredId, ownerId: alice }));
      const okEvents = new RecordingEventPublisher();
      const proposeOk = makeProposeExchange({
        exchanges: new InMemoryExchangeRepository(),
        copies: available,
        ids: new SequentialIdGenerator(),
        events: okEvents,
        clock: new FixedClock(NOW),
      });
      const okRes = await proposeOk({
        initiatorId: alice,
        recipientId: bob,
        kind,
        requestedCopyId: requestedId,
        terms,
      });
      expect(okRes.isOk).toBe(true);
      expect(okEvents.names()).toEqual(["ExchangeProposed"]);

      // unavailable ⇒ reject
      const unavailable = new FakeCopyPort()
        .seed(copy({ id: requestedId, ownerId: bob }))
        .seed(copy({ id: offeredId, ownerId: alice }));
      const proposeReject = makeProposeExchange({
        exchanges: new InMemoryExchangeRepository(),
        copies: unavailable,
        ids: new SequentialIdGenerator(),
        events: new RecordingEventPublisher(),
        clock: new FixedClock(NOW),
      });
      const rejectRes = await proposeReject({
        initiatorId: alice,
        recipientId: bob,
        kind,
        requestedCopyId: requestedId,
        terms,
      });
      expect(rejectRes.isErr).toBe(true);
      if (rejectRes.isErr)
        expect(rejectRes.error.code).toBe("CopyNotAvailable");
    });
  });

  it("rejects a swap whose offered copy is not owned by the initiator", async () => {
    copies
      .seed(
        copy({
          id: requestedId,
          ownerId: bob,
          availability: { forTrade: true, forSale: false, forLend: false },
        }),
      )
      .seed(copy({ id: offeredId, ownerId: bob })); // offered owned by recipient, not initiator

    const result = await propose({
      initiatorId: alice,
      recipientId: bob,
      kind: "swap",
      requestedCopyId: requestedId,
      terms: swapTerms,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("OfferedCopyNotOwned");
  });

  it("rejects a swap whose offered copy does not exist", async () => {
    copies.seed(
      copy({
        id: requestedId,
        ownerId: bob,
        availability: { forTrade: true, forSale: false, forLend: false },
      }),
    );

    const result = await propose({
      initiatorId: alice,
      recipientId: bob,
      kind: "swap",
      requestedCopyId: requestedId,
      terms: swapTerms,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("CopyNotFound");
  });

  it("rejects when the requested copy is not owned by the named recipient", async () => {
    // carol owns the requested copy, but the proposal names bob as the recipient.
    const carol = toMemberId("carol");
    copies
      .seed(
        copy({
          id: requestedId,
          ownerId: carol,
          availability: { forTrade: false, forSale: true, forLend: false },
        }),
      )
      .seed(copy({ id: offeredId, ownerId: alice }));

    const result = await propose({
      initiatorId: alice,
      recipientId: bob,
      kind: "sale",
      requestedCopyId: requestedId,
      terms: saleTerms(),
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("RecipientNotOwner");
    expect(events.published).toHaveLength(0);
  });

  it("delegates self-exchange rejection to the aggregate", async () => {
    copies.seed(
      copy({
        id: requestedId,
        ownerId: alice,
        availability: { forTrade: false, forSale: true, forLend: false },
      }),
    );

    const result = await propose({
      initiatorId: alice,
      recipientId: alice,
      kind: "sale",
      requestedCopyId: requestedId,
      terms: saleTerms(),
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("SelfExchange");
    expect(events.published).toHaveLength(0);
  });
});

src/catalog/domain/puzzle-change-proposa.source:
import { describe, expect, it } from "vitest";
import {
  DomainEvent,
  toChangeProposalId,
  toPuzzleDefinitionId,
  toSubmitterId,
} from "../../shared-kernel";
import { ChangeProposalFiled, ChangeProposalRejected } from "./events";
import {
  FileChangeProposalProps,
  PuzzleChangeProposal,
} from "./puzzle-change-proposal";

const id = toChangeProposalId("cp1");
const definitionId = toPuzzleDefinitionId("pd1");
const proposer = toSubmitterId("alice");
const NOW = new Date("2026-07-08T10:00:00Z");
const LATER = new Date("2026-07-09T10:00:00Z");

const names = (events: readonly DomainEvent[]): string[] =>
  events.map((e) => e.name);

const file = (
  overrides: Partial<FileChangeProposalProps> = {},
): PuzzleChangeProposal => {
  const r = PuzzleChangeProposal.file({
    id,
    puzzleDefinitionId: definitionId,
    proposedBy: proposer,
    changes: { title: "Corrected Title" },
    baseline: { title: "Old Title" },
    now: NOW,
    ...overrides,
  });
  if (!r.isOk) throw new Error(`setup failed: ${r.error.message}`);
  return r.value;
};

describe("PuzzleChangeProposal.file", () => {
  it("starts pending and records ChangeProposalFiled with definition + proposer", () => {
    const proposal = file({ comment: "box says 500" });
    expect(proposal.status).toBe("pending");
    expect(proposal.toState().comment).toBe("box says 500");
    const events = proposal.pullEvents();
    expect(names(events)).toEqual(["ChangeProposalFiled"]);
    const filed = events[0] as ChangeProposalFiled;
    expect(filed.changeProposalId).toBe(id);
    expect(filed.puzzleDefinitionId).toBe(definitionId);
    expect(filed.proposedBy).toBe(proposer);
    expect(filed.occurredAt).toBe(NOW);
  });

  it("rejects an empty diff", () => {
    const r = PuzzleChangeProposal.file({
      id,
      puzzleDefinitionId: definitionId,
      proposedBy: proposer,
      changes: {},
      baseline: {},
      now: NOW,
    });
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("EmptyProposal");
  });

  it("runs the definition's own invariants: blank title, bad piece count, bad barcode", () => {
    const blank = PuzzleChangeProposal.file({
      id,
      puzzleDefinitionId: definitionId,
      proposedBy: proposer,
      changes: { title: "   " },
      baseline: {},
      now: NOW,
    });
    expect(blank.isErr).toBe(true);
    if (blank.isErr) expect(blank.error.code).toBe("EmptyTitle");

    const pieces = PuzzleChangeProposal.file({
      id,
      puzzleDefinitionId: definitionId,
      proposedBy: proposer,
      changes: { pieceCount: -5 },
      baseline: {},
      now: NOW,
    });
    expect(pieces.isErr).toBe(true);
    if (pieces.isErr) expect(pieces.error.code).toBe("InvalidPieceCount");

    const barcode = PuzzleChangeProposal.file({
      id,
      puzzleDefinitionId: definitionId,
      proposedBy: proposer,
      changes: { barcodes: { ean: "not-an-ean" } },
      baseline: {},
      now: NOW,
    });
    expect(barcode.isErr).toBe(true);
    if (barcode.isErr) expect(barcode.error.code).toBe("InvalidBarcode");
  });
});

describe("edit", () => {
  it("replaces changes, baseline and comment in place on a pending proposal", () => {
    const proposal = file();
    proposal.pullEvents();
    const r = proposal.edit(
      { pieceCount: 500 },
      { pieceCount: 1000 },
      "recount",
      LATER,
    );
    expect(r.isOk).toBe(true);
    const state = proposal.toState();
    expect(state.changes).toEqual({ pieceCount: 500 });
    expect(state.baseline).toEqual({ pieceCount: 1000 });
    expect(state.comment).toBe("recount");
    expect(state.updatedAt).toBe(LATER);
    expect(names(proposal.pullEvents())).toEqual(["ChangeProposalEdited"]);
  });

  it("re-validates the new diff (empty diff rejected)", () => {
    const proposal = file();
    const r = proposal.edit({}, {}, undefined, LATER);
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("EmptyProposal");
  });

  it("clears the comment when the edit omits it", () => {
    const proposal = file({ comment: "original rationale" });
    proposal.pullEvents();
    const r = proposal.edit({ title: "X" }, { title: "Old" }, undefined, LATER);
    expect(r.isOk).toBe(true);
    expect(proposal.toState().comment).toBeUndefined();
  });

  it("cannot edit a decided or withdrawn proposal", () => {
    const approved = file();
    approved.approve(NOW);
    const r1 = approved.edit({ title: "X" }, {}, undefined, LATER);
    expect(r1.isErr).toBe(true);
    if (r1.isErr) expect(r1.error.code).toBe("ProposalNotPending");

    const withdrawn = file();
    withdrawn.withdraw(NOW);
    const r2 = withdrawn.edit({ title: "X" }, {}, undefined, LATER);
    expect(r2.isErr).toBe(true);
    if (r2.isErr) expect(r2.error.code).toBe("ProposalNotPending");
  });
});

describe("decision lifecycle", () => {
  it("approve moves pending → approved, stamps decidedAt, records ChangeProposalApproved", () => {
    const proposal = file();
    proposal.pullEvents();
    const r = proposal.approve(LATER);
    expect(r.isOk).toBe(true);
    expect(proposal.status).toBe("approved");
    expect(proposal.toState().decidedAt).toBe(LATER);
    expect(names(proposal.pullEvents())).toEqual(["ChangeProposalApproved"]);
  });

  it("reject stores the reason, stamps decidedAt, records ChangeProposalRejected carrying it", () => {
    const proposal = file();
    proposal.pullEvents();
    const r = proposal.reject("duplicate of an existing fix", LATER);
    expect(r.isOk).toBe(true);
    expect(proposal.status).toBe("rejected");
    expect(proposal.toState().rejectionReason).toBe(
      "duplicate of an existing fix",
    );
    expect(proposal.toState().decidedAt).toBe(LATER);
    const events = proposal.pullEvents();
    expect(names(events)).toEqual(["ChangeProposalRejected"]);
    expect((events[0] as ChangeProposalRejected).reason).toBe(
      "duplicate of an existing fix",
    );
  });

  it("withdraw moves pending → withdrawn without decidedAt", () => {
    const proposal = file();
    proposal.pullEvents();
    const r = proposal.withdraw(LATER);
    expect(r.isOk).toBe(true);
    expect(proposal.status).toBe("withdrawn");
    expect(proposal.toState().decidedAt).toBeUndefined();
    expect(names(proposal.pullEvents())).toEqual(["ChangeProposalWithdrawn"]);
  });

  it.each([
    ["approve", (p: PuzzleChangeProposal) => p.approve(LATER)],
    ["reject", (p: PuzzleChangeProposal) => p.reject(undefined, LATER)],
    ["withdraw", (p: PuzzleChangeProposal) => p.withdraw(LATER)],
  ])("%s is illegal on an already-decided proposal", (_label, act) => {
    const proposal = file();
    proposal.approve(NOW);
    const r = act(proposal);
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("IllegalProposalTransition");
  });
});

describe("rehydrate/toState round-trip", () => {
  it("preserves every field", () => {
    const proposal = file({ comment: "why" });
    const state = proposal.toState();
    const back = PuzzleChangeProposal.rehydrate(state);
    expect(back.toState()).toEqual(state);
    expect(back.pullEvents()).toEqual([]);
  });
});

describe("getters", () => {
  it("expose id, puzzleDefinitionId, proposedBy, status and changes", () => {
    const proposal = file();
    expect(proposal.id).toBe(id);
    expect(proposal.puzzleDefinitionId).toBe(definitionId);
    expect(proposal.proposedBy).toBe(proposer);
    expect(proposal.status).toBe("pending");
    expect(proposal.changes).toEqual({ title: "Corrected Title" });
  });
});

describe("hasAnyChange with only explicitly-undefined members", () => {
  it("rejects filing a diff whose only keys are explicitly undefined", () => {
    const r = PuzzleChangeProposal.file({
      id,
      puzzleDefinitionId: definitionId,
      proposedBy: proposer,
      changes: { title: undefined, brand: undefined },
      baseline: {},
      now: NOW,
    });
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("EmptyProposal");
  });

  it("rejects editing to a diff whose only keys are explicitly undefined", () => {
    const proposal = file();
    const r = proposal.edit({ title: undefined }, {}, undefined, LATER);
    expect(r.isErr).toBe(true);
    if (r.isErr) expect(r.error.code).toBe("EmptyProposal");
  });
});

