import { beforeEach, describe, expect, it } from "vitest";
import { toCopyId, toExchangeId, toMemberId } from "../../../shared-kernel";
import { Exchange } from "../../domain";
import {
  FixedClock,
  InMemoryExchangeRepository,
  RecordingEventPublisher,
} from "../testing";
import { makeAcceptExchange } from "./accept-exchange";
import { makeCancelExchange } from "./cancel-exchange";
import { makeConfirmCompletion } from "./confirm-completion";
import { makeDeclineExchange } from "./decline-exchange";
import { makeRaiseDispute } from "./raise-dispute";

const alice = toMemberId("alice"); // initiator
const bob = toMemberId("bob"); // recipient
const eve = toMemberId("eve"); // outsider
const requestedId = toCopyId("requested");
const exId = toExchangeId("ex-1");
const NOW = new Date("2026-06-08T10:00:00Z");
const LATER = new Date("2026-06-09T10:00:00Z");

// A proposed swap exchange, persisted, ready for a lifecycle action.
const seedProposed = async (
  repo: InMemoryExchangeRepository,
): Promise<void> => {
  const result = Exchange.propose({
    id: exId,
    initiator: alice,
    recipient: bob,
    requestedCopyId: requestedId,
    terms: { kind: "lend", returnDate: LATER },
    now: NOW,
  });
  if (!result.isOk) throw new Error("setup");
  result.value.pullEvents();
  await repo.save(result.value);
};

const seedAccepted = async (
  repo: InMemoryExchangeRepository,
): Promise<void> => {
  await seedProposed(repo);
  const ex = await repo.findById(exId);
  if (!ex) throw new Error("setup");
  ex.accept(bob, NOW);
  ex.pullEvents();
  await repo.save(ex);
};

const harness = () => {
  const repo = new InMemoryExchangeRepository();
  const events = new RecordingEventPublisher();
  const clock = new FixedClock(NOW);
  return { repo, events, clock, exchanges: repo };
};

describe("makeAcceptExchange", () => {
  let h: ReturnType<typeof harness>;
  beforeEach(() => (h = harness()));

  it("accepts a proposed exchange, persisting and publishing ExchangeAccepted", async () => {
    await seedProposed(h.repo);
    const result = await makeAcceptExchange(h)({
      exchangeId: exId,
      actingMemberId: bob,
    });
    expect(result.isOk).toBe(true);
    expect(h.events.names()).toEqual(["ExchangeAccepted"]);
    expect((await h.repo.findById(exId))?.status).toBe("accepted");
  });

  it("returns ExchangeNotFound when no exchange exists", async () => {
    const result = await makeAcceptExchange(h)({
      exchangeId: exId,
      actingMemberId: bob,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("ExchangeNotFound");
  });

  it("delegates wrong-party rejection to the aggregate", async () => {
    await seedProposed(h.repo);
    const result = await makeAcceptExchange(h)({
      exchangeId: exId,
      actingMemberId: alice,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("WrongParty");
    expect(h.events.published).toHaveLength(0);
  });

  it("delegates illegal-transition rejection to the aggregate", async () => {
    await seedAccepted(h.repo);
    const result = await makeAcceptExchange(h)({
      exchangeId: exId,
      actingMemberId: bob,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("IllegalTransition");
  });
});

describe("makeDeclineExchange", () => {
  let h: ReturnType<typeof harness>;
  beforeEach(() => (h = harness()));

  it("declines a proposed exchange, publishing ExchangeRejected", async () => {
    await seedProposed(h.repo);
    const result = await makeDeclineExchange(h)({
      exchangeId: exId,
      actingMemberId: bob,
    });
    expect(result.isOk).toBe(true);
    expect(h.events.names()).toEqual(["ExchangeRejected"]);
    expect((await h.repo.findById(exId))?.status).toBe("rejected");
  });

  it("returns ExchangeNotFound when no exchange exists", async () => {
    const result = await makeDeclineExchange(h)({
      exchangeId: exId,
      actingMemberId: bob,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("ExchangeNotFound");
  });
});

describe("makeCancelExchange", () => {
  let h: ReturnType<typeof harness>;
  beforeEach(() => (h = harness()));

  it("lets the initiator cancel, publishing ExchangeCancelled", async () => {
    await seedProposed(h.repo);
    const result = await makeCancelExchange(h)({
      exchangeId: exId,
      actingMemberId: alice,
    });
    expect(result.isOk).toBe(true);
    expect(h.events.names()).toEqual(["ExchangeCancelled"]);
    expect((await h.repo.findById(exId))?.status).toBe("cancelled");
  });

  it("delegates wrong-party rejection to the aggregate", async () => {
    await seedProposed(h.repo);
    const result = await makeCancelExchange(h)({
      exchangeId: exId,
      actingMemberId: bob,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("WrongParty");
  });
});

describe("makeRaiseDispute", () => {
  let h: ReturnType<typeof harness>;
  beforeEach(() => (h = harness()));

  it("lets a party dispute an accepted exchange, publishing DisputeRaised", async () => {
    await seedAccepted(h.repo);
    const result = await makeRaiseDispute(h)({
      exchangeId: exId,
      actingMemberId: alice,
    });
    expect(result.isOk).toBe(true);
    expect(h.events.names()).toEqual(["DisputeRaised"]);
    expect((await h.repo.findById(exId))?.status).toBe("disputed");
  });

  it("delegates wrong-party rejection to the aggregate", async () => {
    await seedAccepted(h.repo);
    const result = await makeRaiseDispute(h)({
      exchangeId: exId,
      actingMemberId: eve,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("WrongParty");
  });
});

describe("makeConfirmCompletion (dual confirmation)", () => {
  let h: ReturnType<typeof harness>;
  beforeEach(() => (h = harness()));

  it("first confirmation keeps the exchange accepted and emits no completion events", async () => {
    await seedAccepted(h.repo);
    const result = await makeConfirmCompletion(h)({
      exchangeId: exId,
      actingMemberId: alice,
    });
    expect(result.isOk).toBe(true);
    expect((await h.repo.findById(exId))?.status).toBe("accepted");
    expect(h.events.published).toHaveLength(0);
  });

  it("second confirmation completes and publishes ExchangeCompleted + PossessionTransferred", async () => {
    await seedAccepted(h.repo);
    const confirm = makeConfirmCompletion(h);

    await confirm({ exchangeId: exId, actingMemberId: alice });
    h.clock.set(LATER); // second confirmation happens later
    const result = await confirm({ exchangeId: exId, actingMemberId: bob });

    expect(result.isOk).toBe(true);
    expect((await h.repo.findById(exId))?.status).toBe("completed");
    // the seeded exchange is a lend → possession (not ownership) of the requested copy moves
    expect(h.events.names()).toEqual([
      "ExchangeCompleted",
      "PossessionTransferred",
    ]);
  });

  it("returns ExchangeNotFound when no exchange exists", async () => {
    const result = await makeConfirmCompletion(h)({
      exchangeId: exId,
      actingMemberId: alice,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("ExchangeNotFound");
  });

  it("delegates illegal-transition rejection (confirming a proposed exchange)", async () => {
    await seedProposed(h.repo);
    const result = await makeConfirmCompletion(h)({
      exchangeId: exId,
      actingMemberId: alice,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("IllegalTransition");
  });
});

src/library/application/use-cases/loan-u.source:
import { beforeEach, describe, expect, it } from "vitest";
import {
  err,
  toCopyId,
  toLoanId,
  toOwnerId,
  toPuzzleDefinitionId,
} from "../../../shared-kernel";
import {
  CatalogSnapshot,
  Copy,
  CopyId,
  LibraryError,
  LoanId,
} from "../../domain";
import {
  FixedClock,
  InMemoryCopyRepository,
  InMemoryLoanRepository,
  RecordingEventPublisher,
  SequentialLoanIdGenerator,
} from "../testing";
import { makeOpenLoan } from "./open-loan";
import { makeRecallLoan } from "./recall-loan";
import { makeReturnLoan } from "./return-loan";

const owner = toOwnerId("alice");
const borrower = toOwnerId("bob");
const definitionId = toPuzzleDefinitionId("def1");
const NOW = new Date("2026-06-08T10:00:00Z");
const LATER = new Date("2026-06-20T10:00:00Z");

const snapshot = (): CatalogSnapshot =>
  CatalogSnapshot.create({
    puzzleDefinitionId: definitionId,
    title: "Owl",
    pieceCount: 500,
  });

describe("loan use cases", () => {
  let copies: InMemoryCopyRepository;
  let loans: InMemoryLoanRepository;
  let events: RecordingEventPublisher;
  let copyId: CopyId;

  beforeEach(async () => {
    copies = new InMemoryCopyRepository();
    loans = new InMemoryLoanRepository();
    events = new RecordingEventPublisher();
    const acquired = Copy.acquire({
      id: toCopyId("copy-seed"),
      ownerId: owner,
      snapshot: snapshot(),
      condition: "good",
      now: NOW,
    });
    if (!acquired.isOk) throw new Error("setup");
    copyId = acquired.value.id;
    await copies.save(acquired.value);
  });

  const open = () =>
    makeOpenLoan({
      copies,
      loans,
      ids: new SequentialLoanIdGenerator(),
      events,
      clock: new FixedClock(NOW),
    });

  describe("makeOpenLoan", () => {
    it("opens a loan, moves possession to the borrower, keeps ownership", async () => {
      const result = await open()({ copyId, borrowerId: borrower });
      expect(result.isOk).toBe(true);
      expect(events.names()).toEqual(["LoanOpened", "CopyLentOut"]);
      const copy = await copies.findById(copyId);
      expect(copy?.heldBy).toBe(borrower);
      expect(copy?.ownerId).toBe(owner);
    });

    it("rejects an unknown copy", async () => {
      const result = await open()({
        copyId: toCopyId("ghost"),
        borrowerId: borrower,
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CopyNotFound");
    });

    it("rejects lending a copy to its own owner (CannotLendToSelf)", async () => {
      const result = await open()({ copyId, borrowerId: owner });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CannotLendToSelf");
      expect(events.published).toHaveLength(0);
    });
  });

  describe("closing a loan (return / recall)", () => {
    let loanId: LoanId;

    beforeEach(async () => {
      const opened = await open()({ copyId, borrowerId: borrower });
      if (opened.isOk) loanId = opened.value;
    });

    it("the borrower returns the loan -> possession back to the owner", async () => {
      const result = await makeReturnLoan({
        loans,
        copies,
        events,
        clock: new FixedClock(LATER),
      })({ loanId, actingMemberId: borrower });
      expect(result.isOk).toBe(true);
      expect((await copies.findById(copyId))?.heldBy).toBe(owner);
      expect(events.names()).toEqual(
        expect.arrayContaining(["LoanClosed", "CopyReturnedToOwner"]),
      );
    });

    it("still closes the loan when the copy no longer exists", async () => {
      await copies.remove(copyId);
      const result = await makeReturnLoan({
        loans,
        copies,
        events,
        clock: new FixedClock(LATER),
      })({ loanId, actingMemberId: borrower });
      expect(result.isOk).toBe(true);
      // Exactly the loan close is published — no copy events when the copy is gone.
      expect(events.names()).toEqual([
        "LoanOpened",
        "CopyLentOut",
        "LoanClosed",
      ]);
    });

    it("recall still closes the loan when the copy no longer exists", async () => {
      await copies.remove(copyId);
      const result = await makeRecallLoan({
        loans,
        copies,
        events,
        clock: new FixedClock(LATER),
      })({ loanId, actingMemberId: owner });
      expect(result.isOk).toBe(true);
      expect(events.names()).toEqual([
        "LoanOpened",
        "CopyLentOut",
        "LoanClosed",
      ]);
    });

    it("a non-borrower cannot return", async () => {
      const result = await makeReturnLoan({
        loans,
        copies,
        events,
        clock: new FixedClock(LATER),
      })({ loanId, actingMemberId: owner });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("NotBorrower");
    });

    it("the owner recalls the loan -> possession back to the owner", async () => {
      const result = await makeRecallLoan({
        loans,
        copies,
        events,
        clock: new FixedClock(LATER),
      })({ loanId, actingMemberId: owner });
      expect(result.isOk).toBe(true);
      expect((await copies.findById(copyId))?.heldBy).toBe(owner);
      expect(events.names()).toEqual(
        expect.arrayContaining(["LoanClosed", "CopyReturnedToOwner"]),
      );
    });

    it("a non-owner cannot recall", async () => {
      const result = await makeRecallLoan({
        loans,
        copies,
        events,
        clock: new FixedClock(LATER),
      })({ loanId, actingMemberId: borrower });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("NotLender");
    });

    it("rejects closing an unknown loan", async () => {
      const result = await makeReturnLoan({
        loans,
        copies,
        events,
        clock: new FixedClock(LATER),
      })({ loanId: toLoanId("ghost"), actingMemberId: borrower });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("LoanNotFound");
    });

    it("rejects recalling an unknown loan", async () => {
      const result = await makeRecallLoan({
        loans,
        copies,
        events,
        clock: new FixedClock(LATER),
      })({ loanId: toLoanId("ghost"), actingMemberId: owner });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("LoanNotFound");
    });

    // returnToOwner returns a Result; both close use cases must propagate a failure rather than
    // silently swallow it and still report ok. Wrap the repo so the loaded copy fails to return.
    const failingReturnCopies = (): InMemoryCopyRepository => {
      const wrapped = copies;
      return {
        ...wrapped,
        findById: async (id: CopyId) => {
          const copy = await wrapped.findById(id);
          if (copy) {
            copy.returnToOwner = () => err(LibraryError.notOwner("return"));
          }
          return copy;
        },
      } as InMemoryCopyRepository;
    };

    it("propagates a returnToOwner failure on return (does not report ok)", async () => {
      const result = await makeReturnLoan({
        loans,
        copies: failingReturnCopies(),
        events,
        clock: new FixedClock(LATER),
      })({ loanId, actingMemberId: borrower });
      expect(result.isErr).toBe(true);
    });

    it("propagates a returnToOwner failure on recall (does not report ok)", async () => {
      const result = await makeRecallLoan({
        loans,
        copies: failingReturnCopies(),
        events,
        clock: new FixedClock(LATER),
      })({ loanId, actingMemberId: owner });
      expect(result.isErr).toBe(true);
    });
  });
});

